(globalThis.TURBOPACK||(globalThis.TURBOPACK=[])).push(["object"==typeof document?document.currentScript:void 0,575777,e=>{"use strict";e.s(["ALL_DIALOGUES",0,[{id:"dlg-a1-greetings-001",level:"A1",situation:"greetings",context:{en:"Meeting a friend",ko:"친구를 만남"},prompt:{en:"How are you?",ko:"잘 지내?"},template:"I'm {0}, thank you.",blanks:[[{en:"great",ko:"좋아",note:"활기차고 아주 긍정적인 느낌"},{en:"good",ko:"잘 지내",note:"무난하고 안전한 기본 대답"},{en:"okay",ko:"그럭저럭",note:"솔직하게 보통일 때, 친구 사이"}]],example:{en:"I'm great, thank you!",ko:"잘 지내, 고마워!"},alternatives:[{en:"Pretty good!",ko:"꽤 좋아!",note:"가볍고 캐주얼한 강조"},{en:"Not bad.",ko:"나쁘지 않아.",note:"겸손하거나 무덤덤한 뉘앙스"}]},{id:"dlg-a1-greetings-002",level:"A1",situation:"greetings",context:{en:"Being introduced to someone",ko:"누군가를 소개받음"},prompt:{en:"Nice to meet you!",ko:"만나서 반가워요!"},template:"Nice to meet you {0}!",blanks:[[{en:"too",ko:"저도",note:"가장 흔하고 편한 기본 표현"},{en:"as well",ko:"저 역시",note:"조금 더 점잖고 차분한 느낌"}]],example:{en:"Nice to meet you too!",ko:"저도 만나서 반가워요!"},alternatives:[{en:"Likewise!",ko:"저도요!",note:"짧고 세련된 한마디 대답"},{en:"The pleasure is mine.",ko:"제가 더 반가워요.",note:"아주 정중하고 격식 차린 인사"}]},{id:"dlg-a1-food-001",level:"A1",situation:"food",context:{en:"Ordering at a cafe",ko:"카페에서 주문"},prompt:{en:"What can I get you?",ko:"뭐 드릴까요?"},template:"I'd like a {0} and a {1}.",blanks:[[{en:"coffee",ko:"커피",note:"카페에서 가장 흔한 주문"},{en:"tea",ko:"차",note:"커피 대신 차를 원할 때"}],[{en:"sandwich",ko:"샌드위치",note:"간단한 식사가 될 메뉴"},{en:"cookie",ko:"쿠키",note:"가볍게 곁들이는 달콤한 간식"},{en:"muffin",ko:"머핀",note:"커피와 잘 어울리는 빵류"}]],example:{en:"I'd like a coffee and a sandwich.",ko:"커피랑 샌드위치 주세요."},alternatives:[{en:"Can I get a coffee, please?",ko:"커피 한 잔 주시겠어요?",note:"공손하게 부탁하는 기본 주문"},{en:"A tea for me, thanks.",ko:"저는 차로 할게요.",note:"여럿이 있을 때 내 것만 고를 때"}]},{id:"dlg-a1-shopping-001",level:"A1",situation:"shopping",context:{en:"Asking the price in a shop",ko:"가게에서 가격을 물음"},prompt:{en:"Can I help you?",ko:"도와드릴까요?"},template:"How {0} is {1}?",blanks:[[{en:"much",ko:"얼마",note:"가격 물을 때 쓰는 정해진 단어"}],[{en:"this",ko:"이거",note:"내 손 가까이 있는 물건"},{en:"that",ko:"저거",note:"조금 떨어져 있는 물건"},{en:"it",ko:"그거",note:"이미 말한 그 물건을 가리킬 때"}]],example:{en:"How much is this?",ko:"이거 얼마예요?"},alternatives:[{en:"What's the price?",ko:"가격이 어떻게 돼요?",note:"가격만 콕 집어 묻는 표현"},{en:"How much does it cost?",ko:"얼마인가요?",note:"값을 묻는 또박또박한 완전한 문장"}]},{id:"dlg-a1-directions-001",level:"A1",situation:"directions",context:{en:"Asking for directions",ko:"길을 물음"},prompt:{en:"Excuse me, do you need help?",ko:"실례합니다, 도움이 필요하세요?"},template:"Yes, where is the {0}?",blanks:[[{en:"station",ko:"역",note:"지하철·기차역을 찾을 때"},{en:"restroom",ko:"화장실",note:"화장실을 점잖게 이르는 말"},{en:"bus stop",ko:"버스 정류장",note:"버스 타는 곳을 찾을 때"},{en:"exit",ko:"출구",note:"건물·역에서 나가는 곳을 찾을 때"}]],example:{en:"Yes, where is the station?",ko:"네, 역이 어디예요?"},alternatives:[{en:"How do I get to the station?",ko:"역에 어떻게 가요?",note:"가는 길·방법을 물을 때"},{en:"Is the station near here?",ko:"역이 근처에 있어요?",note:"가까운지부터 확인할 때"}]},{id:"dlg-a1-requests-001",level:"A1",situation:"requests",context:{en:"Arriving late to meet someone",ko:"약속에 늦게 도착"},prompt:{en:"You're late!",ko:"늦었네!"},template:"I'm {0}, I'm late.",blanks:[[{en:"sorry",ko:"미안해",note:"가볍게 사과하는 기본 표현"},{en:"so sorry",ko:"정말 미안해",note:"더 진심으로 강조해 사과할 때"}]],example:{en:"I'm sorry, I'm late.",ko:"미안해, 늦었어."},alternatives:[{en:"Sorry to keep you waiting.",ko:"기다리게 해서 미안해.",note:"기다리게 한 점을 콕 집어 사과"},{en:"My apologies.",ko:"죄송합니다.",note:"짧지만 정중하고 격식 있는 사과"}]},{id:"dlg-a1-greetings-003",level:"A1",situation:"greetings",context:{en:"Saying goodbye",ko:"헤어질 때"},prompt:{en:"I have to go now.",ko:"이제 가봐야 해."},template:"Okay, see you {0}!",blanks:[[{en:"later",ko:"나중에",note:"언제일지 정하지 않은 편한 작별"},{en:"tomorrow",ko:"내일",note:"내일 또 만나기로 했을 때"},{en:"soon",ko:"곧",note:"머지않아 또 보자는 느낌"}]],example:{en:"Okay, see you later!",ko:"그래, 나중에 봐!"},alternatives:[{en:"Take care!",ko:"잘 가!",note:"몸 잘 챙기라는 따뜻한 작별"},{en:"Have a good one!",ko:"좋은 시간 보내!",note:"친구끼리 가볍게 던지는 인사"}]},{id:"dlg-a1-requests-002",level:"A1",situation:"requests",context:{en:"Someone offers to help with a heavy bag",ko:"무거운 짐을 도와준다고 함"},prompt:{en:"Do you need a hand?",ko:"도와줄까요?"},template:"Yes, can you help me {0} this?",blanks:[[{en:"carry",ko:"옮기다",note:"들고 다른 곳으로 나를 때"},{en:"lift",ko:"들다",note:"위로 들어 올리는 동작에 초점"},{en:"move",ko:"옮기다",note:"위치만 바꿀 때 두루 쓰는 말"}]],example:{en:"Yes, can you help me carry this?",ko:"네, 이거 옮기는 것 좀 도와주실래요?"},alternatives:[{en:"Could you give me a hand?",ko:"좀 도와주실래요?",note:"공손하게 도움을 청하는 표현"},{en:"That would be a big help.",ko:"그래 주시면 큰 도움이 돼요.",note:"고마움을 미리 전하며 부탁"}]},{id:"dlg-a1-food-002",level:"A1",situation:"food",context:{en:"Ordering at a restaurant",ko:"식당에서 주문"},prompt:{en:"Are you ready to order?",ko:"주문하시겠어요?"},template:"Yes, I'll {0} the {1}.",blanks:[[{en:"have",ko:"먹다",note:"주문할 때 가장 자연스러운 말"},{en:"get",ko:"시키다",note:"조금 더 가볍고 캐주얼한 느낌"},{en:"try",ko:"먹어보다",note:"처음 먹어보고 싶을 때"}],[{en:"chicken",ko:"치킨",note:"무난하게 많이 고르는 메뉴"},{en:"pasta",ko:"파스타",note:"면 요리를 고를 때"},{en:"steak",ko:"스테이크",note:"조금 특별하게 먹고 싶을 때"}]],example:{en:"Yes, I'll have the chicken.",ko:"네, 치킨으로 할게요."},alternatives:[{en:"The pasta, please.",ko:"파스타 주세요.",note:"메뉴만 짧게 말하는 간단 주문"},{en:"Can I get the steak?",ko:"스테이크 주시겠어요?",note:"공손하게 물어보듯 주문할 때"}]},{id:"dlg-a1-smalltalk-001",level:"A1",situation:"small-talk",context:{en:"A coworker greets you in the morning",ko:"아침에 동료가 인사함"},prompt:{en:"Good morning! How's it going?",ko:"좋은 아침! 어떻게 지내요?"},template:"Morning! I'm a bit {0}, but {1}.",blanks:[[{en:"tired",ko:"피곤한",note:"몸이 지쳐 힘들 때 두루 쓰는 말"},{en:"sleepy",ko:"졸린",note:"잠이 덜 깨 졸릴 때 콕 집어"},{en:"busy",ko:"바쁜",note:"할 일이 많아 정신없을 때"}],[{en:"good",ko:"괜찮아요",note:"그래도 괜찮다는 긍정적 마무리"},{en:"fine",ko:"괜찮아요",note:"별일 없이 무난하다는 느낌"},{en:"okay",ko:"그럭저럭이에요",note:"딱히 좋지도 나쁘지도 않을 때"}]],example:{en:"Morning! I'm a bit tired, but good.",ko:"좋은 아침! 좀 피곤하지만 괜찮아요."},alternatives:[{en:"Pretty good, thanks!",ko:"꽤 좋아요, 고마워요!",note:"밝게 잘 지낸다고 답할 때"},{en:"Same as always.",ko:"늘 똑같죠 뭐.",note:"평소와 다름없다는 편한 대답"}]},{id:"dlg-a2-weather-001",level:"A2",situation:"weather",context:{en:"Talking about the weather outside",ko:"바깥 날씨 이야기"},prompt:{en:"What's the weather like today?",ko:"오늘 날씨 어때?"},template:"It's {0} and a little {1}.",blanks:[[{en:"sunny",ko:"맑은",note:"해가 쨍한 화창한 날"},{en:"cloudy",ko:"흐린",note:"구름 많고 흐린 날"},{en:"rainy",ko:"비 오는",note:"비가 내리는 날"}],[{en:"cold",ko:"추운",note:"쌀쌀하고 추울 때"},{en:"warm",ko:"따뜻한",note:"포근하고 기분 좋은 날씨"},{en:"windy",ko:"바람 부는",note:"바람이 많이 부는 날"}]],example:{en:"It's sunny and a little cold.",ko:"맑고 조금 추워."},alternatives:[{en:"It might rain later.",ko:"이따 비 올지도 몰라.",note:"확신 없이 추측할 때"},{en:"The weather is really nice today.",ko:"오늘 날씨 정말 좋아.",note:"날씨를 적극 칭찬하는 느낌"}]},{id:"dlg-a2-hobbies-001",level:"A2",situation:"hobbies",context:{en:"Chatting about free time",ko:"여가 시간에 대해 잡담"},prompt:{en:"What do you do on weekends?",ko:"주말에 뭐 해?"},template:"I usually {0} or watch some {1}.",blanks:[[{en:"read books",ko:"책을 읽다",note:"차분하고 정적인 취미"},{en:"go hiking",ko:"등산을 가다",note:"활동적이고 야외 활동"},{en:"play games",ko:"게임을 하다",note:"캐주얼하고 가벼운 여가"}],[{en:"movies",ko:"영화",note:"한 편으로 끝나는 영화"},{en:"TV shows",ko:"드라마",note:"여러 회차 드라마·시리즈물"},{en:"videos",ko:"영상",note:"유튜브 등 짧은 영상"}]],example:{en:"I usually read books or watch some movies.",ko:"보통 책을 읽거나 영화를 좀 봐."},alternatives:[{en:"I like to relax at home.",ko:"집에서 쉬는 걸 좋아해.",note:"집순이/집돌이 느낌, 무난"},{en:"I often meet my friends.",ko:"친구들을 자주 만나.",note:"사교적이고 활동적인 인상"}]},{id:"dlg-a2-phone-001",level:"A2",situation:"phone",context:{en:"Answering a call for a coworker who is out",ko:"자리를 비운 동료에게 온 전화를 받음"},prompt:{en:"Can I speak to Mr. Kim, please?",ko:"김 선생님과 통화할 수 있을까요?"},template:"Sorry, he's not here. Can I take a {0}?",blanks:[[{en:"message",ko:"메시지",note:"전화 통화에서 가장 흔한 표현"},{en:"note",ko:"메모",note:"짧게 적어두는 메모 느낌"}]],example:{en:"Sorry, he's not here. Can I take a message?",ko:"죄송해요, 지금 안 계세요. 메시지 남기시겠어요?"},alternatives:[{en:"He'll be back soon.",ko:"곧 돌아오실 거예요.",note:"안심시키며 기다리라는 뉘앙스"},{en:"Can you call again later?",ko:"나중에 다시 전화 주시겠어요?",note:"재통화를 정중히 부탁"}]},{id:"dlg-a2-health-001",level:"A2",situation:"health",context:{en:"A friend looks unwell",ko:"친구가 아파 보임"},prompt:{en:"You don't look so good. Are you okay?",ko:"안색이 안 좋아 보여. 괜찮아?"},template:"I have a {0}. I think I should {1}.",blanks:[[{en:"headache",ko:"두통",note:"머리가 아플 때"},{en:"cold",ko:"감기",note:"콧물·기침 등 감기 증상"},{en:"fever",ko:"열",note:"몸에 열이 날 때"}],[{en:"rest",ko:"쉬다",note:"가볍게 쉬면 될 정도"},{en:"see a doctor",ko:"병원에 가다",note:"꽤 안 좋아 진료가 필요할 때"},{en:"go home",ko:"집에 가다",note:"지금 자리를 떠나 귀가할 때"}]],example:{en:"I have a headache. I think I should rest.",ko:"두통이 있어. 좀 쉬어야 할 것 같아."},alternatives:[{en:"I'm not feeling well today.",ko:"오늘 몸이 좀 안 좋아.",note:"증상을 콕 집지 않고 두루뭉술"},{en:"I'll be fine after some sleep.",ko:"좀 자고 나면 괜찮아질 거야.",note:"걱정 말라며 가볍게 넘길 때"}]},{id:"dlg-a2-transport-001",level:"A2",situation:"transport",context:{en:"Asking how someone gets to work",ko:"회사에 어떻게 가는지 물음"},prompt:{en:"How do you get to work?",ko:"회사에 어떻게 가요?"},template:"I take the {0}. It takes about {1} minutes.",blanks:[[{en:"subway",ko:"지하철",note:"도시 안 지하철 이용"},{en:"bus",ko:"버스",note:"버스로 출퇴근할 때"},{en:"train",ko:"기차",note:"도시 간 기차 이동"}],[{en:"twenty",ko:"20",note:"비교적 가까운 거리"},{en:"thirty",ko:"30",note:"적당히 걸리는 거리"},{en:"forty",ko:"40",note:"꽤 먼 편"}]],example:{en:"I take the subway. It takes about twenty minutes.",ko:"지하철 타요. 20분쯤 걸려요."},alternatives:[{en:"I usually walk if it's close.",ko:"가까우면 보통 걸어가요.",note:"조건을 덧붙인 답변"},{en:"Sometimes I drive my car.",ko:"가끔은 차를 운전해요.",note:"가끔 예외가 있을 때"}]},{id:"dlg-a2-family-001",level:"A2",situation:"family",context:{en:"Talking about your family",ko:"가족에 대해 이야기"},prompt:{en:"Do you have any brothers or sisters?",ko:"형제자매가 있어?"},template:"Yes, I have an older {0}. We {1} well.",blanks:[[{en:"brother",ko:"형/오빠",note:"남자 형제일 때"},{en:"sister",ko:"누나/언니",note:"여자 형제일 때"}],[{en:"get along",ko:"잘 지내다",note:"사이가 좋다는 관계 표현"},{en:"get on",ko:"잘 지내다",note:"'get along'과 같은 뜻, 영국식에서 흔함"}]],example:{en:"Yes, I have an older brother. We get along well.",ko:"응, 형이 한 명 있어. 우리는 사이좋게 지내."},alternatives:[{en:"I'm an only child.",ko:"나는 외동이야.",note:"형제가 없을 때 쓰는 정해진 표현"},{en:"My family is pretty big.",ko:"우리 가족은 꽤 대가족이야.",note:"식구가 많다고 가볍게 말할 때"}]},{id:"dlg-a2-shopping-001",level:"A2",situation:"shopping",context:{en:"Trying on clothes in a store",ko:"가게에서 옷을 입어봄"},prompt:{en:"How does it fit?",ko:"잘 맞으세요?"},template:"It's a bit too {0}. Do you have a {1} size?",blanks:[[{en:"small",ko:"작은",note:"전체적으로 사이즈가 작을 때"},{en:"big",ko:"큰",note:"전체적으로 사이즈가 클 때"},{en:"tight",ko:"꽉 끼는",note:"조여서 몸에 딱 붙을 때"}],[{en:"bigger",ko:"더 큰",note:"한 치수 키우고 싶을 때"},{en:"smaller",ko:"더 작은",note:"한 치수 줄이고 싶을 때"},{en:"different",ko:"다른",note:"사이즈를 콕 집지 않고 바꿔달라 할 때"}]],example:{en:"It's a bit too small. Do you have a bigger size?",ko:"조금 작네요. 더 큰 사이즈 있나요?"},alternatives:[{en:"Can I try another color?",ko:"다른 색 입어봐도 돼요?",note:"다른 선택지를 더 보고 싶을 때"},{en:"I'll think about it, thanks.",ko:"좀 생각해 볼게요, 감사합니다.",note:"정중히 거절하거나 보류할 때"}]},{id:"dlg-a2-invitations-001",level:"A2",situation:"invitations",context:{en:"A friend invites you out",ko:"친구가 놀러 가자고 함"},prompt:{en:"Do you want to come to my party on Friday?",ko:"금요일에 내 파티에 올래?"},template:"Sure, I'd {0} to! What time should I {1}?",blanks:[[{en:"love",ko:"정말 ~하고 싶다",note:"아주 신나게 수락하는 느낌"},{en:"like",ko:"~하고 싶다",note:"차분하게 수락할 때"}],[{en:"come",ko:"오다",note:"가장 쉽고 일상적인 표현"},{en:"be there",ko:"도착하다",note:"그 자리에 가 있겠다는 뉘앙스"},{en:"arrive",ko:"도착하다",note:"약간 더 격식 있는 '도착하다'"}]],example:{en:"Sure, I'd love to! What time should I come?",ko:"좋아, 정말 가고 싶어! 몇 시에 가면 돼?"},alternatives:[{en:"That sounds fun!",ko:"재밌겠다!",note:"들뜬 마음을 가볍게 표현"},{en:"Sorry, I'm busy that day.",ko:"미안, 그날은 바빠.",note:"정중히 거절하는 기본 표현"}]},{id:"dlg-a2-daily-routine-001",level:"A2",situation:"daily-routine",context:{en:"Talking about your morning",ko:"아침 일과에 대해 이야기"},prompt:{en:"What time do you wake up?",ko:"몇 시에 일어나?"},template:"I wake up at {0} and then I {1}.",blanks:[[{en:"seven",ko:"7시",note:"보통의 기상 시간"},{en:"six thirty",ko:"6시 30분",note:"조금 이른 기상"},{en:"eight",ko:"8시",note:"여유 있게 늦게 일어날 때"}],[{en:"make breakfast",ko:"아침을 만들다",note:"직접 요리해 챙겨 먹을 때"},{en:"take a shower",ko:"샤워를 하다",note:"씻으며 하루를 시작할 때"},{en:"check my phone",ko:"휴대폰을 확인하다",note:"솔직한 요즘 아침 습관"}]],example:{en:"I wake up at seven and then I make breakfast.",ko:"7시에 일어나서 아침을 만들어."},alternatives:[{en:"I'm not a morning person.",ko:"나는 아침형 인간이 아니야.",note:"아침이 힘들다고 솔직히 말할 때"},{en:"I always need coffee first.",ko:"나는 항상 커피부터 마셔야 해.",note:"습관을 가볍게 강조"}]},{id:"dlg-a2-feelings-001",level:"A2",situation:"feelings",context:{en:"A friend shares some news",ko:"친구가 소식을 전함"},prompt:{en:"I just got a new job!",ko:"나 새 직장 구했어!"},template:"That's {0} news! I'm so {1} for you.",blanks:[[{en:"great",ko:"좋은",note:"무난하게 자주 쓰는 칭찬"},{en:"wonderful",ko:"멋진",note:"조금 더 따뜻하고 정성스러운 느낌"},{en:"amazing",ko:"굉장한",note:"감탄이 강한 최상급 반응"}],[{en:"happy",ko:"기쁜",note:"잔잔하고 진심 어린 기쁨"},{en:"excited",ko:"신나는",note:"들뜨고 활기찬 기쁨"},{en:"pleased",ko:"기쁜",note:"happy보다 차분하고 점잖은 기쁨"}]],example:{en:"That's great news! I'm so happy for you.",ko:"정말 좋은 소식이다! 진심으로 기뻐."},alternatives:[{en:"Congratulations!",ko:"축하해!",note:"성취를 축하하는 정해진 한마디"},{en:"You really deserve it.",ko:"넌 그럴 자격이 충분해.",note:"노력을 인정하며 칭찬할 때"}]},{id:"dlg-b1-work-001",level:"B1",situation:"work",context:{en:"A colleague asks how a project is going",ko:"동료가 프로젝트 진행 상황을 물음"},prompt:{en:"How's the new project coming along?",ko:"새 프로젝트는 어떻게 돼 가요?"},template:"It's going {0}, but we still need to {1} a few things.",blanks:[[{en:"well",ko:"잘",note:"무난하고 일반적인 긍정"},{en:"smoothly",ko:"순조롭게",note:"막힘없이 잘 풀린다는 뉘앙스"},{en:"fine",ko:"괜찮게",note:"그저 그럭저럭, 담백한 톤"}],[{en:"sort out",ko:"정리하다",note:"문제를 풀어 정돈하는 일상 표현"},{en:"finalize",ko:"마무리하다",note:"최종 확정짓는 격식 있는 말"},{en:"double-check",ko:"재확인하다",note:"꼼꼼히 다시 점검하는 느낌"}]],example:{en:"It's going well, but we still need to sort out a few things.",ko:"잘 돼 가는데, 아직 몇 가지 정리할 게 있어요."},alternatives:[{en:"We're on track, more or less.",ko:"대체로 일정대로 가고 있어요.",note:"대략 순조롭다는 가벼운 보고"},{en:"There's a lot left, but we're getting there.",ko:"남은 게 많지만 점점 나아지고 있어요.",note:"솔직하면서 긍정적인 마무리"}]},{id:"dlg-b1-opinions-001",level:"B1",situation:"opinions",context:{en:"A friend asks what you think of a movie",ko:"친구가 영화에 대한 의견을 물음"},prompt:{en:"So, what did you think of the film?",ko:"그래서 그 영화 어땠어?"},template:"Honestly, I thought it was {0}, mainly because the {1} was so {2}.",blanks:[[{en:"great",ko:"훌륭했다",note:"흔히 쓰는 무난한 호평"},{en:"impressive",ko:"인상적이었다",note:"완성도에 감탄하는 뉘앙스"},{en:"disappointing",ko:"실망스러웠다",note:"기대에 못 미쳤다는 부정 평가"}],[{en:"story",ko:"이야기",note:"줄거리·각본을 가리킴"},{en:"acting",ko:"연기",note:"배우의 연기에 초점"},{en:"ending",ko:"결말",note:"마지막 장면·결말에 초점"}],[{en:"moving",ko:"감동적인",note:"마음을 울리는 긍정 평가"},{en:"predictable",ko:"뻔한",note:"예상대로라 아쉽다는 부정"},{en:"well done",ko:"잘 만들어진",note:"솜씨 좋다는 담백한 칭찬"}]],example:{en:"Honestly, I thought it was great, mainly because the story was so moving.",ko:"솔직히 훌륭하다고 생각했어. 이야기가 정말 감동적이었거든."},alternatives:[{en:"It wasn't really my kind of thing.",ko:"내 취향은 아니었어.",note:"직접 비판은 피하며 완곡하게"},{en:"I'd definitely watch it again.",ko:"또 볼 만한 영화였어.",note:"재관람 의향으로 강한 호평"}]},{id:"dlg-b1-plans-001",level:"B1",situation:"plans",context:{en:"A coworker invites you out after work",ko:"동료가 퇴근 후 약속을 제안"},prompt:{en:"Do you want to grab dinner after work?",ko:"퇴근하고 저녁 먹을래요?"},template:"I'd love to, but I {0} today, so maybe we could {1} instead.",blanks:[[{en:"have plans",ko:"약속이 있다",note:"구체적 이유 없이 정중한 거절"},{en:"'m a bit busy",ko:"좀 바쁘다",note:"가볍게 둘러대는 캐주얼"},{en:"promised to help a friend",ko:"친구를 돕기로 했다",note:"이유를 분명히 밝혀 미안함 전달"}],[{en:"do it tomorrow",ko:"내일 하다",note:"바로 다음 날로 미루는 적극 제안"},{en:"meet next week",ko:"다음 주에 만나다",note:"여유 있게 미루는 느낌"},{en:"grab a quick coffee now",ko:"지금 커피만 빨리 마시다",note:"짧게라도 보려는 절충안"}]],example:{en:"I'd love to, but I have plans today, so maybe we could do it tomorrow instead.",ko:"그러고 싶은데 오늘은 약속이 있어요. 대신 내일 하는 건 어때요?"},alternatives:[{en:"Can we take a rain check?",ko:"다음으로 미뤄도 될까요?",note:"다음을 기약하는 친근한 관용구"},{en:"Let's set something up for later this week.",ko:"이번 주 후반에 약속 잡아요.",note:"대안을 먼저 내미는 적극적 톤"}]},{id:"dlg-b1-problems-001",level:"B1",situation:"problems",context:{en:"A friend notices you look stressed",ko:"친구가 당신이 스트레스 받아 보인다고 함"},prompt:{en:"You seem stressed. Is everything okay?",ko:"스트레스 받아 보여. 다 괜찮아?"},template:"Not really, I've been {0} lately, and I'm not sure how to {1} it.",blanks:[[{en:"overwhelmed",ko:"벅찬",note:"감정에 압도된 솔직한 토로"},{en:"under a lot of pressure",ko:"압박을 많이 받는",note:"외부 압박을 강조하는 표현"},{en:"struggling with work",ko:"일 때문에 힘든",note:"원인을 일로 콕 집어 말함"}],[{en:"deal with",ko:"감당하다",note:"두루 쓰는 일반적인 대처"},{en:"handle",ko:"처리하다",note:"차분히 다룬다는 담백한 톤"},{en:"get on top of",ko:"통제하다",note:"상황을 다잡으려는 구어체"}]],example:{en:"Not really, I've been overwhelmed lately, and I'm not sure how to deal with it.",ko:"사실 아니야. 요즘 좀 벅차서 어떻게 감당해야 할지 모르겠어."},alternatives:[{en:"It's a lot to take in right now.",ko:"지금 감당할 게 너무 많아.",note:"벅참을 완곡하게 표현"},{en:"I just need to clear my head.",ko:"머리를 좀 식혀야 할 것 같아.",note:"혼자 정리할 시간이 필요한 뉘앙스"}]},{id:"dlg-b1-restaurant-001",level:"B1",situation:"restaurant",context:{en:"A waiter asks about your meal",ko:"종업원이 식사가 어떤지 물음"},prompt:{en:"How is everything tasting?",ko:"음식은 입맛에 맞으세요?"},template:"It's {0}, thank you, though the {1} could be a little {2}.",blanks:[[{en:"delicious",ko:"맛있다",note:"맛 자체를 콕 집은 칭찬"},{en:"really good",ko:"정말 좋다",note:"편하게 만족을 전하는 캐주얼"},{en:"lovely",ko:"훌륭하다",note:"따뜻하고 다정한 영국식 칭찬"}],[{en:"soup",ko:"수프",note:"수프 요리를 가리킴"},{en:"sauce",ko:"소스",note:"곁들인 소스에 초점"},{en:"main dish",ko:"메인 요리",note:"메인 요리 전체를 가리킴"}],[{en:"warmer",ko:"더 따뜻한",note:"온도에 대한 부드러운 요청"},{en:"saltier",ko:"더 짠",note:"간을 더 해달라는 뉘앙스"},{en:"spicier",ko:"더 매운",note:"매운맛을 더 원할 때"}]],example:{en:"It's delicious, thank you, though the soup could be a little warmer.",ko:"맛있어요, 감사합니다. 다만 수프는 조금 더 따뜻하면 좋겠어요."},alternatives:[{en:"Everything's perfect, thanks.",ko:"다 완벽해요, 고맙습니다.",note:"불만 없이 깔끔하게 만족 표현"},{en:"Could we get a bit more bread?",ko:"빵 조금만 더 주시겠어요?",note:"정중하게 추가를 부탁하는 표현"}]},{id:"dlg-b1-advice-001",level:"B1",situation:"advice",context:{en:"A friend asks for advice about a job offer",ko:"친구가 입사 제안에 대해 조언을 구함"},prompt:{en:"I got a job offer, but I'm not sure. What should I do?",ko:"입사 제안을 받았는데 확신이 안 서. 어떡하지?"},template:"If I were you, I'd {0} it carefully and {1} the pros and cons before you {2}.",blanks:[[{en:"think about",ko:"생각해 보다",note:"두루 쓰는 일상 표현"},{en:"look at",ko:"살펴보다",note:"찬찬히 들여다보는 뉘앙스"},{en:"consider",ko:"고려하다",note:"진지하게 검토하는 격식체"}],[{en:"weigh up",ko:"따져 보다",note:"장단점을 저울질하는 구어체"},{en:"list",ko:"적어 보다",note:"목록으로 정리하는 실용적 방법"},{en:"compare",ko:"비교하다",note:"양쪽을 견주어 보는 표현"}],[{en:"decide",ko:"결정하다",note:"가장 무난한 일반 동사"},{en:"commit",ko:"확정하다",note:"되돌리기 어려운 확약 뉘앙스"},{en:"say yes",ko:"수락하다",note:"수락에 한정한 캐주얼 표현"}]],example:{en:"If I were you, I'd think about it carefully and weigh up the pros and cons before you decide.",ko:"나라면 신중히 생각해 보고, 결정하기 전에 장단점을 따져 볼 거야."},alternatives:[{en:"Trust your gut on this one.",ko:"이건 네 직감을 믿어.",note:"직감을 믿으라는 친근한 조언"},{en:"Maybe sleep on it before deciding.",ko:"결정하기 전에 하룻밤 자면서 생각해 봐.",note:"서두르지 말라는 부드러운 권유"}]},{id:"dlg-b1-travel-001",level:"B1",situation:"travel",context:{en:"Checking in at a hotel",ko:"호텔에서 체크인"},prompt:{en:"Welcome! Is this your first time in the city?",ko:"환영합니다! 이 도시는 처음이세요?"},template:"Yes, it is, and I was hoping you could {0} a good place to {1} nearby.",blanks:[[{en:"recommend",ko:"추천하다",note:"가장 자연스러운 추천 동사"},{en:"suggest",ko:"제안하다",note:"넌지시 권하는 부드러운 톤"},{en:"point me to",ko:"알려 주다",note:"위치를 짚어달라는 구어체"}],[{en:"eat",ko:"식사하다",note:"식당을 찾는 가장 흔한 표현"},{en:"visit",ko:"방문하다",note:"가볼 만한 곳을 두루 가리킴"},{en:"go for a walk",ko:"산책하다",note:"걷기 좋은 곳에 초점"}]],example:{en:"Yes, it is, and I was hoping you could recommend a good place to eat nearby.",ko:"네, 처음이에요. 근처에 식사하기 좋은 곳을 추천해 주실 수 있을까요?"},alternatives:[{en:"What's worth seeing around here?",ko:"이 근처에 볼 만한 곳이 있나요?",note:"볼거리를 묻는 캐주얼한 질문"},{en:"Are there any local spots you'd suggest?",ko:"추천할 만한 현지 명소가 있나요?",note:"현지인 추천을 청하는 정중한 톤"}]},{id:"dlg-b1-experiences-001",level:"B1",situation:"experiences",context:{en:"A friend asks about your recent trip",ko:"친구가 최근 여행에 대해 물음"},prompt:{en:"How was your trip? Tell me everything!",ko:"여행 어땠어? 다 얘기해 줘!"},template:"It was {0}! The best part was when we {1}, and I'd really {2} going there.",blanks:[[{en:"amazing",ko:"놀라웠다",note:"흔하게 쓰는 강한 감탄"},{en:"unforgettable",ko:"잊지 못할 만큼 좋았다",note:"오래 기억에 남는다는 강조"},{en:"exhausting but fun",ko:"힘들었지만 재밌었다",note:"솔직하게 양면을 다 전하는 톤"}],[{en:"hiked up the mountain",ko:"산을 오르다",note:"활동적인 하이라이트"},{en:"tried the local food",ko:"현지 음식을 먹어 보다",note:"음식 경험에 초점"},{en:"watched the sunset",ko:"노을을 보다",note:"감성적인 순간에 초점"}],[{en:"recommend",ko:"추천하다",note:"가장 자연스러운 추천"},{en:"suggest",ko:"권하다",note:"넌지시 권하는 부드러운 톤"},{en:"advise",ko:"권하다",note:"가서 보라고 강하게 권하는 느낌"}]],example:{en:"It was amazing! The best part was when we hiked up the mountain, and I'd really recommend going there.",ko:"정말 놀라웠어! 산에 올랐을 때가 제일 좋았고, 거기 꼭 가보길 추천해."},alternatives:[{en:"I can't wait to go back.",ko:"다시 가고 싶어 죽겠어.",note:"재방문 욕구로 강한 만족 표현"},{en:"I took way too many photos!",ko:"사진을 너무 많이 찍었어!",note:"유쾌하게 즐거움을 전하는 톤"}]},{id:"dlg-b1-phone-calls-001",level:"B1",situation:"phone-calls",context:{en:"Calling a company to ask about a delayed order",ko:"지연된 주문에 대해 회사에 전화함"},prompt:{en:"Thank you for calling. How can I help you today?",ko:"전화 주셔서 감사합니다. 무엇을 도와드릴까요?"},template:"Hi, I'm calling {0} my order, which {1}, and I'd like to know what's going on.",blanks:[[{en:"about",ko:"~에 대해",note:"가장 일상적인 전치사"},{en:"regarding",ko:"~에 관하여",note:"전화·이메일의 격식체"},{en:"to ask about",ko:"~에 대해 물으려고",note:"목적을 분명히 밝히는 표현"}],[{en:"hasn't arrived yet",ko:"아직 도착하지 않았다",note:"사실만 담담히 전달"},{en:"is two weeks late",ko:"2주째 늦고 있다",note:"구체적 지연으로 불만 강조"},{en:"seems to be lost",ko:"분실된 것 같다",note:"단정 대신 추측으로 완곡하게"}]],example:{en:"Hi, I'm calling about my order, which hasn't arrived yet, and I'd like to know what's going on.",ko:"안녕하세요, 아직 도착하지 않은 제 주문 건으로 전화드렸는데요, 어떻게 된 건지 알고 싶어요."},alternatives:[{en:"Could you check the status for me, please?",ko:"상태 좀 확인해 주시겠어요?",note:"정중하게 확인을 부탁하는 표현"},{en:"I'd appreciate an update on this.",ko:"이 건에 대한 안내를 받을 수 있으면 좋겠어요.",note:"공손하게 후속 안내를 청함"}]},{id:"dlg-b1-appointments-001",level:"B1",situation:"appointments",context:{en:"Rescheduling a doctor's appointment by phone",ko:"전화로 병원 예약을 변경함"},prompt:{en:"Your appointment is on Friday at 3. Does that still work?",ko:"예약이 금요일 3시인데, 그대로 괜찮으세요?"},template:"Actually, something came up, so could we {0} it to {1} if that's possible?",blanks:[[{en:"move",ko:"옮기다",note:"쉽고 무난한 일상 표현"},{en:"reschedule",ko:"변경하다",note:"예약 변경의 격식 있는 말"},{en:"push",ko:"미루다",note:"뒤로 미룬다는 구어체"}],[{en:"Monday morning",ko:"월요일 오전",note:"구체적 시간대를 콕 집음"},{en:"next week",ko:"다음 주",note:"여유 있게 다음 주로"},{en:"later that afternoon",ko:"그날 오후 늦게",note:"같은 날 안에서 조정"}]],example:{en:"Actually, something came up, so could we move it to Monday morning if that's possible?",ko:"사실 일이 생겨서요, 가능하다면 월요일 오전으로 옮길 수 있을까요?"},alternatives:[{en:"Is there any availability earlier in the week?",ko:"주 초반에 가능한 시간이 있나요?",note:"앞당길 수 있는지 묻는 정중한 질문"},{en:"Whatever slot works best for you is fine.",ko:"되는 시간 아무 때나 괜찮아요.",note:"상대에 맞춰주는 유연한 태도"}]},{id:"dlg-b2-business-001",level:"B2",situation:"business",context:{en:"A client asks for an aggressive deadline",ko:"고객이 촉박한 마감을 요청함"},prompt:{en:"Can you have the whole report ready by Friday?",ko:"금요일까지 보고서 전체를 끝낼 수 있나요?"},template:"I'd say that's {0}, though we'd need to {1} the {2} accordingly.",blanks:[[{en:"feasible",ko:"실현 가능한",note:"격식 있고 분석적인 어감"},{en:"doable",ko:"할 수 있는",note:"편하고 일상적인 구어체"},{en:"realistic",ko:"현실적인",note:"현실성을 따지는 신중한 뉘앙스"}],[{en:"adjust",ko:"조정하다",note:"가장 무난한 일반적 표현"},{en:"revisit",ko:"재검토하다",note:"다시 들여다본다는 완곡한 어감"},{en:"reprioritise",ko:"우선순위를 다시 정하다",note:"격식 있는 비즈니스 용어"}],[{en:"scope",ko:"범위",note:"일의 양·범위를 가리킴"},{en:"timeline",ko:"일정",note:"기한·일정에 초점"},{en:"deliverables",ko:"산출물",note:"결과물 단위로 보는 격식체"}]],example:{en:"I'd say that's feasible, though we'd need to adjust the scope accordingly.",ko:"실현 가능하다고 봅니다. 다만 그에 맞춰 범위를 조정해야 할 거예요."},alternatives:[{en:"That's tight, but I think we can make it work.",ko:"촉박하긴 하지만 어떻게든 맞출 수 있을 것 같아요.",note:"솔직하면서도 긍정적인 자신감"},{en:"Let me confirm with the team and get back to you.",ko:"팀과 확인하고 다시 말씀드리겠습니다.",note:"즉답을 피하고 신중하게 미루는 표현"}]},{id:"dlg-b2-meetings-001",level:"B2",situation:"meetings",context:{en:"A colleague proposes a plan you partly disagree with",ko:"동료가 일부 동의하기 어려운 계획을 제안함"},prompt:{en:"So we'd cut the testing phase to save two weeks. Thoughts?",ko:"테스트 단계를 줄여서 2주를 절약하자는 거예요. 어떻게 생각해요?"},template:"I see where you're coming from, but I'm {0} that we might {1} the {2}.",blanks:[[{en:"concerned",ko:"우려하는",note:"격식 있게 우려를 표하는 어감"},{en:"worried",ko:"걱정하는",note:"감정이 더 직접 드러나는 구어체"},{en:"uneasy",ko:"꺼림칙한",note:"막연히 마음이 편치 않은 완곡한 어감"}],[{en:"compromise",ko:"훼손하다",note:"품질을 떨어뜨린다는 일반적 표현"},{en:"undermine",ko:"약화시키다",note:"서서히 기반을 무너뜨리는 어감"},{en:"overlook",ko:"간과하다",note:"놓치고 지나친다는 뉘앙스"}],[{en:"quality",ko:"품질",note:"결과물의 완성도에 초점"},{en:"results",ko:"결과",note:"최종 성과 전반을 가리킴"},{en:"stability",ko:"안정성",note:"안정·신뢰성 측면을 강조"}]],example:{en:"I see where you're coming from, but I'm concerned that we might compromise the quality.",ko:"무슨 말씀인지는 알겠지만, 품질을 훼손할까 봐 우려됩니다."},alternatives:[{en:"Could we find a middle ground instead?",ko:"대신 절충안을 찾아볼 수 있을까요?",note:"협력적으로 타협을 제안하는 어감"},{en:"I'd want to weigh the risks before committing.",ko:"결정하기 전에 위험을 따져 보고 싶어요.",note:"결정을 미루며 신중함을 강조"}]},{id:"dlg-b2-discussion-001",level:"B2",situation:"discussion",context:{en:"A friend asks whether remote work is better",ko:"친구가 재택근무가 더 나은지 물음"},prompt:{en:"Honestly, isn't working from home just better for everyone?",ko:"솔직히 재택근무가 모두한테 그냥 더 낫지 않아?"},template:"It {0} on the person, really — some people {1}, while others {2}.",blanks:[[{en:"depends",ko:"달려 있다",note:"가장 일반적이고 무난한 표현"},{en:"varies",ko:"다르다",note:"경우마다 제각각이라는 어감"},{en:"hinges",ko:"좌우된다",note:"한 요인에 크게 달렸다는 강조"}],[{en:"thrive",ko:"잘 해낸다",note:"오히려 더 활약한다는 긍정 강조"},{en:"focus better",ko:"더 잘 집중한다",note:"집중력 측면에 초점"},{en:"stay motivated",ko:"동기를 유지한다",note:"의욕·동기 유지에 초점"}],[{en:"feel isolated",ko:"고립감을 느낀다",note:"외로움·단절감을 가리킴"},{en:"struggle to switch off",ko:"일을 끄기 어려워한다",note:"일과 휴식 분리가 안 됨"},{en:"miss the structure",ko:"체계를 그리워한다",note:"규칙적 틀의 부재를 아쉬워함"}]],example:{en:"It depends on the person, really — some people thrive, while others feel isolated.",ko:"사실 사람마다 달라. 어떤 사람은 잘 해내고, 어떤 사람은 고립감을 느끼거든."},alternatives:[{en:"There are clear upsides, but it's not for everyone.",ko:"분명한 장점이 있지만 모두에게 맞는 건 아니야.",note:"장점을 인정하되 단서를 다는 균형"},{en:"I think a hybrid setup gets the best of both.",ko:"내 생각엔 하이브리드가 양쪽의 장점을 다 가져가는 것 같아.",note:"절충안을 적극 추천하는 어감"}]},{id:"dlg-b2-news-001",level:"B2",situation:"news",context:{en:"Discussing a headline about rising prices",ko:"물가 상승 기사를 두고 이야기함"},prompt:{en:"Did you see prices are climbing again this quarter?",ko:"이번 분기에 물가가 또 오르고 있다는 거 봤어?"},template:"I did, and it's {0} that wages aren't {1} the same {2}.",blanks:[[{en:"frustrating",ko:"답답한",note:"개인적 짜증·답답함을 드러냄"},{en:"troubling",ko:"걱정스러운",note:"더 진지하게 우려하는 어감"},{en:"telling",ko:"시사하는 바가 큰",note:"내막을 드러낸다는 분석적 표현"}],[{en:"keeping up at",ko:"따라가지 못하는",note:"뒤처지지 않고 따라간다는 뜻"},{en:"rising at",ko:"오르지 않는",note:"상승 속도 자체에 초점"},{en:"matching",ko:"맞추지 못하는",note:"같은 수준으로 맞춘다는 어감"}],[{en:"pace",ko:"속도",note:"변화의 빠르기에 초점"},{en:"rate",ko:"비율",note:"수치·비율로 보는 표현"},{en:"level",ko:"수준",note:"도달한 정도·수준을 가리킴"}]],example:{en:"I did, and it's frustrating that wages aren't keeping up at the same pace.",ko:"봤어. 임금이 같은 속도로 따라가지 못한다는 게 답답해."},alternatives:[{en:"It makes you wonder how long this can last.",ko:"이게 얼마나 갈 수 있을지 궁금해지게 만들어.",note:"회의적인 의문을 던지는 어감"},{en:"Apparently it's a global trend, not just here.",ko:"여기뿐 아니라 전 세계적인 흐름인 것 같아.",note:"전해 들은 정보를 덧붙이는 표현"}]},{id:"dlg-b2-socializing-001",level:"B2",situation:"socializing",context:{en:"Declining a party invitation politely",ko:"파티 초대를 정중히 거절함"},prompt:{en:"We're throwing a get-together on Saturday — you in?",ko:"토요일에 모임을 여는데, 올래?"},template:"I'd {0} to, but I'm afraid I've already {1} something that {2}.",blanks:[[{en:"love",ko:"정말 가고 싶다",note:"현재형, 강하게 가고 싶은 마음"},{en:"have loved",ko:"정말 가고 싶었다",note:"가정법, 못 가서 아쉬운 어감"},{en:"really like",ko:"꽤 가고 싶다",note:"love보다 덜 열렬한 어감"}],[{en:"committed to",ko:"약속한",note:"확실히 약속을 잡았다는 격식체"},{en:"got tied up with",ko:"묶여 있는",note:"벗어나기 힘들다는 구어체"},{en:"made plans for",ko:"계획을 잡은",note:"가장 무난한 일상 표현"}],[{en:"evening",ko:"저녁",note:"그날 저녁 시간대를 콕 집음"},{en:"weekend",ko:"주말",note:"주말 전체로 범위가 넓음"},{en:"day",ko:"날",note:"그날 하루를 두루 가리킴"}]],example:{en:"I'd love to, but I'm afraid I've already committed to something that evening.",ko:"정말 가고 싶지만, 아쉽게도 그날 저녁에 이미 약속이 있어."},alternatives:[{en:"Can I take a raincheck this time?",ko:"이번엔 다음으로 미뤄도 될까?",note:"다음을 기약하는 관용적 구어 표현"},{en:"Count me in for the next one, though!",ko:"그래도 다음 번엔 꼭 갈게!",note:"다음엔 꼭 가겠다는 적극적 어감"}]},{id:"dlg-b2-email-001",level:"B2",situation:"email",context:{en:"Replying to a follow-up email about a delay",ko:"지연에 대한 후속 이메일에 답장함"},prompt:{en:"Just checking in — any update on the figures we asked for?",ko:"확인차 연락드려요. 요청한 수치에 대해 업데이트가 있나요?"},template:"Apologies for the {0} — I'll have the figures {1} to you {2}.",blanks:[[{en:"delay",ko:"지연",note:"가장 무난한 격식 있는 사과어"},{en:"hold-up",ko:"지체",note:"막혀서 늦어진 느낌의 구어체"},{en:"wait",ko:"기다림",note:"기다리게 한 점에 초점"}],[{en:"over",ko:"보내",note:"send over, 자연스러운 구어 표현"},{en:"across",ko:"전달",note:"건네 보낸다는 영국식 구어"},{en:"sent",ko:"발송",note:"가장 단순·직접적인 표현"}],[{en:"by end of day",ko:"오늘 안으로",note:"오늘 마감 시한을 명시"},{en:"first thing tomorrow",ko:"내일 아침 제일 먼저",note:"내일 최우선 처리 약속"},{en:"shortly",ko:"곧",note:"구체 시점 없이 곧이라는 완곡함"}]],example:{en:"Apologies for the delay — I'll have the figures over to you by end of day.",ko:"지연되어 죄송합니다. 오늘 안으로 수치를 보내 드리겠습니다."},alternatives:[{en:"Thanks for your patience; we're almost there.",ko:"기다려 주셔서 감사합니다. 거의 다 됐어요.",note:"감사로 부드럽게 안심시키는 어감"},{en:"I'll loop in my colleague to speed things up.",ko:"속도를 내기 위해 동료를 함께 참조하겠습니다.",note:"구체적 해결책을 제시하는 비즈니스 표현"}]},{id:"dlg-b2-negotiation-001",level:"B2",situation:"negotiation",context:{en:"Negotiating the price of a service",ko:"서비스 가격을 협상함"},prompt:{en:"This is our standard rate. Does that work for you?",ko:"이게 저희 표준 요금입니다. 괜찮으신가요?"},template:"If you could be {0} on the price, I'd be happy to {1} a longer {2}.",blanks:[[{en:"flexible",ko:"유연한",note:"가장 무난한 협상 표현"},{en:"open",ko:"열린",note:"여지를 둔다는 부드러운 어감"},{en:"willing to move",ko:"조정할 의향이 있는",note:"양보 의사를 직접 드러냄"}],[{en:"commit to",ko:"약속하다",note:"확실히 약정하겠다는 강한 어감"},{en:"sign up for",ko:"계약하다",note:"계약에 응한다는 구어 표현"},{en:"consider",ko:"고려하다",note:"검토해 보겠다는 유보적 표현"}],[{en:"contract",ko:"계약",note:"정식 계약서 자체를 가리킴"},{en:"term",ko:"기간",note:"계약 기간 길이에 초점"},{en:"commitment",ko:"약정",note:"지속적 약속·헌신을 강조"}]],example:{en:"If you could be flexible on the price, I'd be happy to commit to a longer contract.",ko:"가격을 좀 유연하게 해 주신다면, 기꺼이 더 긴 계약을 약속드릴게요."},alternatives:[{en:"Is there any room to negotiate on that figure?",ko:"그 금액에 협상의 여지가 좀 있을까요?",note:"에둘러 가격 인하를 떠보는 표현"},{en:"What could you offer if we paid upfront?",ko:"저희가 선결제하면 어떤 조건을 제안하실 수 있나요?",note:"조건을 걸어 양보를 유도하는 어감"}]},{id:"dlg-b2-complaints-001",level:"B2",situation:"complaints",context:{en:"Complaining about a faulty product at a store",ko:"매장에서 결함 있는 제품에 대해 항의함"},prompt:{en:"Is there something wrong with your purchase?",ko:"구매하신 제품에 문제가 있으신가요?"},template:"Yes — it {0} working after a week, so I'd like to {1} a {2}.",blanks:[[{en:"stopped",ko:"멈췄다",note:"가장 중립적이고 무난한 표현"},{en:"quit",ko:"작동을 멈췄다",note:"갑자기 꺼졌다는 구어체"},{en:"gave up",ko:"고장 났다",note:"기기가 수명을 다한 듯한 어감"}],[{en:"request",ko:"요청하다",note:"정중하고 격식 있는 표현"},{en:"ask for",ko:"요구하다",note:"직접적이고 일상적인 표현"},{en:"arrange",ko:"처리하다",note:"절차를 잡아 처리한다는 어감"}],[{en:"refund",ko:"환불",note:"돈을 돌려받길 원함"},{en:"replacement",ko:"교체",note:"새 제품으로 바꾸길 원함"},{en:"repair",ko:"수리",note:"고쳐서 쓰길 원함"}]],example:{en:"Yes — it stopped working after a week, so I'd like to request a refund.",ko:"네. 일주일 만에 작동을 멈춰서 환불을 요청하고 싶어요."},alternatives:[{en:"I'd appreciate it if this could be sorted out today.",ko:"오늘 안에 해결해 주시면 감사하겠습니다.",note:"정중하지만 처리 시한을 압박하는 어감"},{en:"Could you point me to your returns policy?",ko:"반품 정책을 안내해 주실 수 있나요?",note:"규정을 확인하려는 차분한 접근"}]},{id:"dlg-b2-interviews-001",level:"B2",situation:"interviews",context:{en:"Answering a strengths question in a job interview",ko:"면접에서 강점 질문에 답함"},prompt:{en:"What would you say is your greatest strength?",ko:"본인의 가장 큰 강점은 무엇이라고 보세요?"},template:"I'd say my ability to {0} under pressure, which has been {1} when {2} tight deadlines.",blanks:[[{en:"stay calm",ko:"침착함을 유지하다",note:"압박 속 평정심을 강조"},{en:"keep focused",ko:"집중을 유지하다",note:"흐트러지지 않는 집중력 강조"},{en:"adapt quickly",ko:"빠르게 적응하다",note:"변화 대응력에 초점"}],[{en:"invaluable",ko:"매우 귀중한",note:"값을 매길 수 없이 귀하다는 강조"},{en:"a real asset",ko:"진정한 강점인",note:"조직에 보탬이 된다는 어감"},{en:"essential",ko:"필수적인",note:"없어선 안 된다는 단호함"}],[{en:"meeting",ko:"맞출 때",note:"마감을 지켜낸다는 어감"},{en:"handling",ko:"감당할 때",note:"능숙하게 다룬다는 어감"},{en:"facing",ko:"직면할 때",note:"맞닥뜨린 상황 자체를 가리킴"}]],example:{en:"I'd say my ability to stay calm under pressure, which has been invaluable when meeting tight deadlines.",ko:"압박 속에서도 침착함을 유지하는 능력이라고 봅니다. 촉박한 마감을 맞출 때 매우 귀중했어요."},alternatives:[{en:"I'm a strong collaborator who brings teams together.",ko:"저는 팀을 하나로 모으는 협업에 강한 사람입니다.",note:"협업·팀워크 강점을 내세움"},{en:"I tend to spot problems before they escalate.",ko:"문제가 커지기 전에 미리 발견하는 편입니다.",note:"선제적 문제 발견력을 강조"}]},{id:"dlg-b2-culture-001",level:"B2",situation:"culture",context:{en:"Explaining a local custom to a visitor",ko:"방문객에게 현지 관습을 설명함"},prompt:{en:"Why does everyone take their shoes off at the door here?",ko:"여기선 왜 다들 문 앞에서 신발을 벗어요?"},template:"It's a {0} custom — it's seen as a way to {1} the home {2}.",blanks:[[{en:"long-standing",ko:"오래된",note:"오랜 세월 이어진 관습 강조"},{en:"deeply rooted",ko:"깊이 뿌리내린",note:"문화 깊숙이 박혔다는 어감"},{en:"widespread",ko:"널리 퍼진",note:"많은 곳에 보편적이라는 어감"}],[{en:"keep",ko:"유지하다",note:"상태를 계속 유지한다는 일반 표현"},{en:"leave",ko:"유지해 두다",note:"그 상태로 남겨둔다는 어감"},{en:"make",ko:"만들다",note:"그렇게 되도록 만든다는 어감"}],[{en:"clean",ko:"깨끗하게",note:"청결 자체를 가리킴"},{en:"tidy",ko:"정돈되게",note:"단정·정리된 상태에 초점"},{en:"more hygienic",ko:"더 위생적으로",note:"위생·건강 측면을 강조"}]],example:{en:"It's a long-standing custom — it's seen as a way to keep the home clean.",ko:"오래된 관습이에요. 집을 깨끗하게 유지하는 방법으로 여겨지죠."},alternatives:[{en:"It might feel unusual at first, but you'll get used to it.",ko:"처음엔 낯설겠지만, 곧 익숙해질 거예요.",note:"낯섦을 인정하며 안심시키는 어감"},{en:"Most homes will have slippers ready for you.",ko:"대부분의 집에는 당신을 위한 슬리퍼가 준비되어 있을 거예요.",note:"실용적인 정보를 덧붙이는 표현"}]},{id:"dlg-c1-negotiation-001",level:"C1",situation:"negotiation",context:{en:"A vendor pushes back on your proposed pricing",ko:"거래처가 제안한 가격에 난색을 표함"},prompt:{en:"Honestly, that figure is well below what we usually accept.",ko:"솔직히 그 금액은 저희가 보통 받아들이는 수준보다 훨씬 낮습니다."},template:"I {0} where you're coming from, but {1} we'd need to {2} the {3}.",blanks:[[{en:"appreciate",ko:"이해하다",note:"상대 입장에 대한 정중한 공감"},{en:"see",ko:"알다",note:"담백하게 이해를 표하는 중립 표현"},{en:"understand",ko:"이해하다",note:"공감을 차분히 인정하는 기본형"}],[{en:"to move forward",ko:"진행하려면",note:"협상을 앞으로 끌고 갈 때"},{en:"to close this",ko:"이걸 마무리하려면",note:"거래 타결을 직접 겨냥할 때"},{en:"realistically",ko:"현실적으로",note:"냉정한 현실 인식을 강조"}],[{en:"revisit",ko:"재검토하다",note:"다시 들여다보자는 부드러운 제안"},{en:"reconsider",ko:"다시 생각하다",note:"입장 재고를 정중히 요청"},{en:"rework",ko:"손보다",note:"실무적으로 다시 다듬자는 뉘앙스"}],[{en:"scope",ko:"범위",note:"일의 범위 자체를 조정 대상으로"},{en:"terms",ko:"조건",note:"계약 조건 전반을 가리킬 때"},{en:"timeline",ko:"일정",note:"시간 일정에 초점을 둘 때"}]],example:{en:"I appreciate where you're coming from, but to move forward we'd need to revisit the scope.",ko:"말씀하신 입장은 충분히 이해하지만, 진행하려면 범위를 재검토해야 할 것 같습니다."},alternatives:[{en:"Perhaps there's a middle ground we can both live with.",ko:"서로 받아들일 수 있는 절충안이 있을 듯합니다.",note:"완곡하게 절충안을 떠보는 표현"},{en:"Let's see if we can meet halfway on this.",ko:"이 부분에서 서로 한 발씩 양보할 수 있는지 봅시다.",note:"서로 양보를 제안하는 구어체"}]},{id:"dlg-c1-presentation-001",level:"C1",situation:"presentation",context:{en:"Closing a quarterly results presentation to the board",ko:"이사회에 분기 실적 발표를 마무리함"},prompt:{en:"So, what's the one takeaway you'd like us to leave with?",ko:"그래서 우리가 기억해야 할 핵심 한 가지는 무엇인가요?"},template:"If there's {0} thing to {1}, it's that the {2} are {3} in our favour.",blanks:[[{en:"one",ko:"한 가지",note:"핵심을 가볍게 짚는 일반적 표현"},{en:"a single",ko:"단 하나의",note:"오직 하나임을 더 강조"}],[{en:"take away",ko:"기억해 갈",note:"발표 마무리의 표준 관용구"},{en:"walk away with",ko:"가져갈",note:"들고 나갈 결론을 강조"},{en:"hold on to",ko:"붙잡을",note:"오래 간직하라는 뉘앙스"}],[{en:"fundamentals",ko:"기초 체력",note:"사업의 근본 펀더멘털을 지칭"},{en:"numbers",ko:"수치",note:"구체적 실적 수치를 강조"},{en:"trends",ko:"추세",note:"흐름·방향성에 초점"}],[{en:"firmly",ko:"확실히",note:"흔들림 없이 견고함을 강조"},{en:"increasingly",ko:"점점 더",note:"갈수록 유리해짐을 강조"},{en:"decidedly",ko:"분명히",note:"단호하고 명백함을 강조"}]],example:{en:"If there's one thing to take away, it's that the fundamentals are firmly in our favour.",ko:"한 가지만 기억하신다면, 기초 체력이 확실히 우리에게 유리하다는 점입니다."},alternatives:[{en:"In short, we're better positioned now than we were a year ago.",ko:"요컨대, 1년 전보다 지금 입지가 훨씬 탄탄합니다.",note:"비교로 깔끔하게 요약하는 표현"},{en:"The headline here is momentum, and it's on our side.",ko:"핵심은 흐름이고, 그 흐름은 우리 편입니다.",note:"한 단어로 임팩트를 주는 마무리"}]},{id:"dlg-c1-persuasion-001",level:"C1",situation:"persuasion",context:{en:"Convincing a skeptical colleague to back a new initiative",ko:"회의적인 동료에게 새 계획을 지지하도록 설득함"},prompt:{en:"I'm not convinced this is worth the disruption it'll cause.",ko:"이게 초래할 혼란을 감수할 만큼 가치가 있는지 모르겠어요."},template:"I hear you, but {0} the {1} far {2} the short-term {3}.",blanks:[[{en:"in the long run",ko:"장기적으로는",note:"장기 시야로 설득할 때"},{en:"honestly",ko:"솔직히",note:"솔직함을 앞세워 신뢰를 줄 때"},{en:"on balance",ko:"전체적으로 보면",note:"종합 판단을 내세우는 차분한 표현"}],[{en:"upside",ko:"이점",note:"잠재적 상승 여지를 강조"},{en:"payoff",ko:"보상",note:"투자 대비 결실을 강조"},{en:"benefits",ko:"이익",note:"일반적이고 무난한 이득 표현"}],[{en:"outweighs",ko:"능가하다",note:"단수 주어와 호응하는 형태"},{en:"outweigh",ko:"능가하다",note:"복수 주어와 호응하는 형태"}],[{en:"growing pains",ko:"초기 진통",note:"성장에 따르는 일시적 고통 관용구"},{en:"disruption",ko:"혼란",note:"업무 차질·혼란을 직접 지칭"},{en:"friction",ko:"마찰",note:"사소한 마찰로 가볍게 표현"}]],example:{en:"I hear you, but in the long run the upside far outweighs the short-term growing pains.",ko:"말씀 이해합니다만, 장기적으로 보면 이점이 단기적인 초기 진통을 훨씬 능가합니다."},alternatives:[{en:"Let me put it this way: standing still carries a bigger risk.",ko:"이렇게 말씀드릴게요. 가만히 있는 게 오히려 더 큰 위험입니다.",note:"관점을 다시 짚어 주는 설득 어법"},{en:"I'd argue the cost of inaction is what we should really worry about.",ko:"정작 걱정해야 할 건 아무것도 하지 않는 데서 오는 대가라고 봅니다.",note:"주장을 정중히 내세우는 논리적 표현"}]},{id:"dlg-c1-conflict-resolution-001",level:"C1",situation:"conflict-resolution",context:{en:"Two team members are at odds and you step in to mediate",ko:"팀원 둘이 대립해 중재에 나섬"},prompt:{en:"We just can't seem to agree on how to handle this.",ko:"이걸 어떻게 처리할지 도무지 합의가 안 돼요."},template:"Let's {0} and {1} on what we {2} agree on before we {3} the rest.",blanks:[[{en:"take a step back",ko:"한 발 물러서다",note:"take a step back 관용구의 표준형"},{en:"step back",ko:"물러서다",note:"step back으로 더 직접적인 표현"}],[{en:"focus",ko:"집중하다",note:"합의점에 초점을 맞추자는 제안"},{en:"build",ko:"쌓아 가다",note:"공통점 위에 차곡차곡 쌓는 뉘앙스"},{en:"agree",ko:"합의하다",note:"합의 자체를 직접 강조"}],[{en:"already",ko:"이미",note:"이미 합의된 부분임을 부각"},{en:"both",ko:"둘 다",note:"양측 공통임을 강조"},{en:"can",ko:"할 수 있는",note:"합의 가능성에 초점"}],[{en:"tackle",ko:"다루다",note:"정면으로 부딪쳐 처리하는 뉘앙스"},{en:"work through",ko:"차근차근 풀다",note:"단계적으로 풀어가는 차분한 표현"},{en:"untangle",ko:"정리하다",note:"얽힌 문제를 풀어낸다는 비유"}]],example:{en:"Let's take a step back and focus on what we already agree on before we tackle the rest.",ko:"한 발 물러서서, 나머지를 다루기 전에 우리가 이미 합의한 부분에 먼저 집중합시다."},alternatives:[{en:"I think we're closer to common ground than it feels right now.",ko:"지금 느끼는 것보다 우리는 공통분모에 더 가까이 있다고 봐요.",note:"긍정적 전망으로 긴장을 누그러뜨림"},{en:"Let's separate the issue from the personalities for a moment.",ko:"잠시 사안과 감정을 분리해서 봅시다.",note:"사안과 감정을 분리하자는 중재 어법"}]},{id:"dlg-c1-leadership-001",level:"C1",situation:"leadership",context:{en:"Rallying a demoralized team after a setback",ko:"좌절을 겪은 팀의 사기를 북돋움"},prompt:{en:"After that result, morale is honestly pretty low.",ko:"그 결과 이후로 사기가 솔직히 많이 떨어졌어요."},template:"I won't {0} it — that {1}. But this is exactly when we {2} what we're {3} of.",blanks:[[{en:"sugarcoat",ko:"포장하다",note:"듣기 좋게 꾸미지 않겠다는 솔직함"},{en:"downplay",ko:"축소하다",note:"심각성을 줄이지 않겠다는 뉘앙스"}],[{en:"stung",ko:"뼈아팠다",note:"따끔하게 아팠던 감정을 생생히"},{en:"hurt",ko:"아팠다",note:"담백하게 아픔을 인정"},{en:"set us back",ko:"우리를 주춤하게 했다",note:"진행이 후퇴했음을 객관적으로"}],[{en:"show",ko:"보여주다",note:"진가를 드러내자는 격려"},{en:"prove",ko:"증명하다",note:"실력을 입증하자는 도전적 어조"},{en:"find out",ko:"알게 되다",note:"스스로 깨닫게 된다는 뉘앙스"}],[{en:"made",ko:"이루어진",note:"what we're made of 관용구의 본형"},{en:"capable",ko:"해낼 능력이 있는",note:"역량을 직접 가리키는 표현"}]],example:{en:"I won't sugarcoat it — that stung. But this is exactly when we show what we're made of.",ko:"포장하지 않을게요. 그건 뼈아팠습니다. 하지만 바로 이런 때 우리의 진가를 보여주는 겁니다."},alternatives:[{en:"Setbacks like this are where good teams turn into great ones.",ko:"이런 좌절이야말로 좋은 팀이 위대한 팀으로 거듭나는 지점입니다.",note:"위기를 기회로 재해석하는 동기부여"},{en:"We learn from it, we regroup, and we come back sharper.",ko:"여기서 배우고, 전열을 가다듬어, 더 날카롭게 돌아옵시다.",note:"행동 계획을 리듬감 있게 제시"}]},{id:"dlg-c1-networking-001",level:"C1",situation:"networking",context:{en:"Reconnecting with a contact you met at a past conference",ko:"예전 컨퍼런스에서 만난 인맥과 다시 연락함"},prompt:{en:"I'm sorry, have we met before? You look familiar.",ko:"죄송한데, 저희 전에 만난 적 있나요? 낯이 익어서요."},template:"We did, {0} — we {1} at last year's summit. I've been {2} to {3}.",blanks:[[{en:"briefly",ko:"잠깐이지만",note:"짧았던 만남임을 가볍게 인정"},{en:"actually",ko:"실은",note:"사실을 환기하며 친근하게"}],[{en:"crossed paths",ko:"마주쳤다",note:"우연히 스친 만남을 가리키는 관용구"},{en:"got talking",ko:"이야기를 나눴다",note:"자연스레 대화로 이어진 만남"},{en:"were introduced",ko:"소개받았다",note:"공식적으로 소개받은 자리"}],[{en:"meaning",ko:"~하려고 마음먹고 있던",note:"줄곧 마음먹어 온 의도를 강조"},{en:"hoping",ko:"바라고 있던",note:"내심 바라 왔다는 부드러운 뉘앙스"},{en:"looking",ko:"기대하던",note:"막연히 ~할 기회를 노려 온 느낌"}],[{en:"reconnect",ko:"다시 연이 닿다",note:"끊긴 인연을 다시 잇자는 표현"},{en:"pick your brain",ko:"조언을 구하다",note:"지혜를 빌리고 싶다는 친근한 관용구"},{en:"follow up",ko:"후속 연락하다",note:"비즈니스식 후속 접촉을 지칭"}]],example:{en:"We did, briefly — we crossed paths at last year's summit. I've been meaning to reconnect.",ko:"네, 잠깐이지만요. 작년 정상회의에서 마주쳤었죠. 다시 연락드리려던 참이었어요."},alternatives:[{en:"No worries — it's been a while, and there were a lot of faces that day.",ko:"괜찮아요. 시간도 꽤 지났고 그날 사람이 워낙 많았으니까요.",note:"상대의 미안함을 편하게 덜어 주는 표현"},{en:"I'd love to catch up properly when you have a moment.",ko:"시간 되실 때 제대로 한번 이야기 나누고 싶어요.",note:"다음 만남을 정중히 청하는 표현"}]},{id:"dlg-c1-diplomacy-001",level:"C1",situation:"diplomacy",context:{en:"Declining a partner's request without damaging the relationship",ko:"관계를 해치지 않으면서 파트너의 요청을 거절함"},prompt:{en:"So can we count on your support for this proposal?",ko:"그럼 이 제안에 대한 귀사의 지지를 기대해도 될까요?"},template:"We're {0} sympathetic to your position, though at this {1} we're {2} to {3} fully.",blanks:[[{en:"genuinely",ko:"진심으로",note:"공감의 진정성을 강조"},{en:"very much",ko:"대단히",note:"공감의 정도를 정중히 강조"},{en:"deeply",ko:"깊이",note:"깊은 공감을 격식 있게"}],[{en:"juncture",ko:"시점",note:"격식 높은 외교적 시점 표현"},{en:"stage",ko:"단계",note:"진행 단계를 가리키는 무난한 표현"},{en:"point",ko:"지점",note:"가장 일상적인 시점 표현"}],[{en:"not in a position",ko:"~할 입장이 아닌",note:"권한·여건상 불가함을 완곡히"},{en:"reluctant",ko:"주저하는",note:"내키지 않음을 부드럽게 시사"},{en:"unable",ko:"~할 수 없는",note:"할 수 없음을 단도직입적으로"}],[{en:"commit",ko:"확약하다",note:"공식적으로 약속한다는 격식체"},{en:"sign on",ko:"동참하다",note:"참여 합류를 가리키는 구어체"},{en:"get behind it",ko:"전적으로 지지하다",note:"적극 지지를 뜻하는 친근한 관용구"}]],example:{en:"We're genuinely sympathetic to your position, though at this juncture we're not in a position to commit fully.",ko:"귀사의 입장에 진심으로 공감합니다만, 현 시점에서 전적으로 확약드리기는 어렵습니다."},alternatives:[{en:"Let's keep the door open and revisit this once things settle.",ko:"여지를 남겨 두고, 상황이 정리되면 다시 논의하시죠.",note:"거절하되 가능성을 열어 두는 표현"},{en:"I'd rather give you an honest 'not yet' than an empty 'yes'.",ko:"공허한 '예'보다는 솔직한 '아직은'을 드리는 편이 낫겠습니다.",note:"솔직함을 내세워 신뢰를 지키는 거절"}]},{id:"dlg-c1-interviews-001",level:"C1",situation:"interviews",context:{en:"Answering the 'biggest weakness' question in a senior interview",ko:"고위직 면접에서 '가장 큰 약점' 질문에 답함"},prompt:{en:"And what would you say is your greatest weakness?",ko:"본인의 가장 큰 약점은 무엇이라고 생각하시나요?"},template:"I've {0} a tendency to {1} too much, and I've learned to {2} it by {3}.",blanks:[[{en:"had",ko:"지녀 온",note:"오랜 경향임을 담담히 인정"},{en:"noticed",ko:"알아챈",note:"스스로 관찰해 깨달았음을 강조"},{en:"owned",ko:"인정해 온",note:"약점을 주체적으로 책임지는 성숙함"}],[{en:"take on",ko:"떠맡다",note:"일을 과하게 떠안는 경향"},{en:"micromanage",ko:"세세히 간섭하다",note:"지나친 세부 관리 성향"},{en:"second-guess myself",ko:"스스로를 의심하다",note:"자기 판단을 거듭 의심하는 성향"}],[{en:"rein in",ko:"다스리다",note:"고삐를 죄듯 절제한다는 관용구"},{en:"keep in check",ko:"통제하다",note:"꾸준히 억제·관리한다는 뉘앙스"},{en:"counter",ko:"보완하다",note:"대응책으로 상쇄한다는 표현"}],[{en:"delegating deliberately",ko:"의식적으로 위임함으로써",note:"의도적 위임으로 해결"},{en:"setting clear boundaries",ko:"명확한 경계를 두어",note:"분명한 선을 그어 해결"},{en:"trusting my team more",ko:"팀을 더 신뢰함으로써",note:"팀 신뢰로 해결하는 리더십"}]],example:{en:"I've had a tendency to take on too much, and I've learned to rein it in by delegating deliberately.",ko:"너무 많은 일을 떠맡는 경향이 있었는데, 의식적으로 위임함으로써 그 점을 다스리는 법을 배웠습니다."},alternatives:[{en:"It's something I actively work on rather than something I've fully solved.",ko:"완전히 해결했다기보다 지금도 적극적으로 개선해 나가는 부분입니다.",note:"현재진행형 노력으로 솔직하게 답변"},{en:"Self-awareness has been half the battle there.",ko:"그 점에서는 스스로를 아는 것이 절반의 성공이었습니다.",note:"자기 인식의 가치를 짚는 관용구"}]},{id:"dlg-c1-workplace-001",level:"C1",situation:"workplace",context:{en:"Pushing back on an unrealistic deadline from your manager",ko:"상사가 제시한 비현실적인 마감에 이의를 제기함"},prompt:{en:"I'll need the full report on my desk by tomorrow morning.",ko:"내일 아침까지 완성된 보고서를 제 책상에 올려놓으세요."},template:"I want to {0} this, but to do it {1} I'd either need {2} or to {3} the scope.",blanks:[[{en:"deliver on",ko:"해내다",note:"약속한 결과를 완수한다는 책임감"},{en:"make",ko:"맞추다",note:"마감을 지킨다는 간결한 표현"},{en:"get behind",ko:"전적으로 따르다",note:"지시에 적극 동참하겠다는 뉘앙스"}],[{en:"properly",ko:"제대로",note:"제대로 해내겠다는 일반적 강조"},{en:"justice",ko:"충실히",note:"do it justice, 충실히 다룬다는 관용구"},{en:"right",ko:"올바르게",note:"제대로 맞게 한다는 담백한 표현"}],[{en:"a bit more time",ko:"조금 더 시간이",note:"추가 시간을 정중히 요청"},{en:"an extra pair of hands",ko:"일손 하나가",note:"추가 인력을 비유적으로 요청"},{en:"until end of day",ko:"퇴근 무렵까지가",note:"구체적 마감 연장을 제시"}],[{en:"trim",ko:"줄이다",note:"군더더기를 쳐내는 가벼운 축소"},{en:"narrow",ko:"좁히다",note:"범위를 좁힌다는 표현"},{en:"scale back",ko:"축소하다",note:"규모 자체를 줄인다는 표현"}]],example:{en:"I want to deliver on this, but to do it properly I'd either need a bit more time or to trim the scope.",ko:"이걸 꼭 해내고 싶습니다만, 제대로 하려면 시간이 조금 더 있거나 범위를 줄여야 할 것 같습니다."},alternatives:[{en:"Happy to prioritise — which sections matter most for tomorrow?",ko:"기꺼이 우선순위를 두겠습니다. 내일 가장 중요한 부분이 어디인가요?",note:"협조 의사를 보이며 우선순위를 되묻는 표현"},{en:"I'd rather flag this now than overpromise and underdeliver.",ko:"과하게 약속하고 못 지키느니 지금 미리 말씀드리는 편이 낫겠습니다.",note:"선제적으로 위험을 알리는 책임감 있는 표현"}]},{id:"dlg-c1-feedback-001",level:"C1",situation:"feedback",context:{en:"Giving constructive criticism to a high performer",ko:"성과가 좋은 직원에게 건설적인 비판을 전함"},prompt:{en:"I thought that presentation went really well, didn't it?",ko:"그 발표 정말 잘됐다고 생각하는데, 안 그래요?"},template:"It {0} a lot of strengths. One thing I'd {1} on is how you {2} pushback — it came across as a touch {3}.",blanks:[[{en:"played to",ko:"잘 살렸다",note:"강점을 잘 활용했다는 관용구"},{en:"showcased",ko:"잘 보여줬다",note:"강점을 돋보이게 드러냈다는 표현"},{en:"had",ko:"갖췄다",note:"강점이 있었다는 담백한 표현"}],[{en:"build",ko:"발전시키다",note:"build on, 이미 좋은 것을 더 키우자는 긍정적 어법"},{en:"work",ko:"손보다",note:"work on, 부담 없이 살짝 손보자는 완곡 표현"},{en:"improve",ko:"개선하다",note:"improve on, 더 낫게 다듬자는 뉘앙스"}],[{en:"handled",ko:"다뤘다",note:"반론을 처리한 방식 전반을 지칭"},{en:"fielded",ko:"받아넘겼다",note:"질문을 능숙히 받아쳤다는 뉘앙스"},{en:"responded to",ko:"대응했다",note:"반응한 방식을 중립적으로 지칭"}],[{en:"defensive",ko:"방어적인",note:"방어적으로 비쳤다는 직접 지적"},{en:"guarded",ko:"경계하는",note:"마음을 닫고 경계한 듯한 인상"},{en:"abrupt",ko:"퉁명스러운",note:"다소 무뚝뚝·성급하게 비친 인상"}]],example:{en:"It played to a lot of strengths. One thing I'd build on is how you handled pushback — it came across as a touch defensive.",ko:"강점이 많이 드러난 발표였어요. 한 가지 발전시킬 점은 반론에 대응하는 방식인데, 다소 방어적으로 비쳤어요."},alternatives:[{en:"Take this as polish on something that's already strong.",ko:"이미 훌륭한 것을 더 다듬는 차원으로 받아들여 주세요.",note:"비판을 긍정적으로 포장해 전하는 표현"},{en:"Next time, try treating tough questions as a chance to shine.",ko:"다음엔 어려운 질문을 빛날 기회로 삼아 보세요.",note:"개선점을 격려로 바꿔 제시하는 표현"}]},{id:"dlg-c2-debate-001",level:"C2",situation:"debate",context:{en:"Rebutting an opponent's claim in a formal debate",ko:"공식 토론에서 상대의 주장을 반박함"},prompt:{en:"Surely you'd concede that deregulation has driven growth?",ko:"규제 완화가 성장을 견인했다는 점은 인정하시겠죠?"},template:"I'd {0} that premise, because the {1} you cite {2} far more than it {3}, and the {4} is, frankly, anecdotal.",blanks:[[{en:"contest",ko:"반박하다",note:"근거를 들어 정면으로 맞서는 격식체"},{en:"challenge",ko:"이의를 제기하다",note:"타당성을 따져 묻는 중립적 표현"},{en:"dispute",ko:"논박하다",note:"사실 여부를 두고 다투는 단호한 어감"}],[{en:"correlation",ko:"상관관계",note:"인과 아닌 통계적 연관을 콕 집음"},{en:"evidence",ko:"증거",note:"주장을 뒷받침하는 일반적 근거"},{en:"data",ko:"자료",note:"수치·관측치 자체를 가리키는 중립어"}],[{en:"obscures",ko:"가린다",note:"진실을 흐려 안 보이게 한다는 뉘앙스"},{en:"oversimplifies",ko:"지나치게 단순화한다",note:"복잡함을 깎아낸다는 비판조"},{en:"distorts",ko:"왜곡한다",note:"사실을 비틀어 놓는다는 강한 비난"}],[{en:"explains",ko:"설명한다",note:"현상의 까닭을 밝힌다는 기본형"},{en:"clarifies",ko:"해명한다",note:"모호함을 또렷이 한다는 어감"},{en:"reveals",ko:"드러낸다",note:"숨은 진실을 들춰낸다는 강조"}],[{en:"rest",ko:"나머지",note:"남은 부분을 가리키는 일상어"},{en:"remainder",ko:"잔여 부분",note:"딱딱하고 문어적인 격식체"},{en:"balance",ko:"그 외",note:"회계·격식 맥락의 점잖은 표현"}]],example:{en:"I'd contest that premise, because the correlation you cite obscures far more than it explains, and the rest is, frankly, anecdotal.",ko:"그 전제에 반박하겠습니다. 인용하신 상관관계는 설명하는 것보다 가리는 게 훨씬 많고, 나머지는 솔직히 일화에 불과하니까요."},alternatives:[{en:"With respect, that conflates correlation with causation.",ko:"외람되지만 그건 상관관계와 인과관계를 혼동하는 겁니다.",note:"정중한 운을 떼고 논리 오류를 짚는 학술조"},{en:"The burden of proof rests with you, not with me.",ko:"입증 책임은 제가 아니라 그쪽에 있습니다.",note:"입증 책임을 되넘기는 토론 정석 표현"},{en:"That's a textbook case of cherry-picking the data.",ko:"그건 자료를 입맛대로 골라낸 전형적인 사례입니다.",note:"유리한 자료만 골랐다고 직격하는 구어 관용구"}]},{id:"dlg-c2-academic-001",level:"C2",situation:"academic",context:{en:"Responding to a question after a research presentation",ko:"연구 발표 후 질문에 답함"},prompt:{en:"How robust are your findings given the sample size?",ko:"표본 크기를 고려하면 결과가 얼마나 견고합니까?"},template:"The findings are {0}, though I'd {1} against {2} them; the effect {3} is modest, and replication would {4} the conclusions.",blanks:[[{en:"preliminary",ko:"예비적인",note:"아직 초기 단계임을 밝히는 학술 표준어"},{en:"tentative",ko:"잠정적인",note:"확정 아닌 임시 결론임을 강조"},{en:"promising",ko:"유망한",note:"긍정적 가능성에 무게를 싣는 어감"}],[{en:"caution",ko:"경계하다",note:"넘지 말라고 점잖게 주의를 주는 격식체"},{en:"warn",ko:"경고하다",note:"위험을 분명히 알리는 강한 어조"},{en:"advise",ko:"권고하다",note:"전문가로서 정중히 조언하는 뉘앙스"}],[{en:"overstating",ko:"과대평가하기",note:"실제보다 부풀려 말함을 경계"},{en:"generalizing",ko:"일반화하기",note:"표본 넘어 함부로 확대 적용함"},{en:"extrapolating",ko:"외삽하기",note:"범위 밖으로 추정하는 학술 전문어"}],[{en:"size",ko:"크기",note:"통계의 'effect size' 정착 용어"},{en:"magnitude",ko:"규모",note:"양적 크기를 격식 있게 표현"},{en:"strength",ko:"강도",note:"효과의 세기를 강조하는 어감"}],[{en:"strengthen",ko:"강화하다",note:"결론을 더 탄탄히 한다는 기본형"},{en:"corroborate",ko:"입증하다",note:"다른 근거로 뒷받침한다는 학술어"},{en:"consolidate",ko:"공고히 하다",note:"여러 결과를 한데 굳힌다는 어감"}]],example:{en:"The findings are preliminary, though I'd caution against overstating them; the effect size is modest, and replication would strengthen the conclusions.",ko:"결과는 예비적입니다. 다만 과대평가하지 않도록 경계하고 싶습니다. 효과 크기가 미미해서, 재현이 이뤄지면 결론이 강화될 것입니다."},alternatives:[{en:"I'd qualify that with the usual caveats about statistical power.",ko:"통계적 검정력에 관한 통상의 단서를 달아 두겠습니다.",note:"관례적 단서를 붙여 주장을 한정하는 학술조"},{en:"The confidence intervals are wider than I'd like.",ko:"신뢰구간이 제가 바라는 것보다 넓습니다.",note:"불확실성을 솔직히 인정하는 완곡 표현"},{en:"Further work is needed before we draw firm conclusions.",ko:"확정적 결론을 내리기 전에 추가 연구가 필요합니다.",note:"논문 결론부의 정형화된 마무리 문구"}]},{id:"dlg-c2-diplomacy-001",level:"C2",situation:"diplomacy",context:{en:"Responding to a counterpart at a bilateral summit",ko:"양자 정상회담에서 상대국 대표에게 응답함"},prompt:{en:"Can your government commit to the proposed timeline?",ko:"귀국 정부가 제안된 일정을 약속할 수 있습니까?"},template:"We {0} the spirit of the proposal and remain {1} to dialogue, but any commitment must be {2} with our domestic {3}, so I'd urge that we {4} the timeline together.",blanks:[[{en:"welcome",ko:"환영하다",note:"긍정적 수용을 따뜻하게 표하는 외교어"},{en:"appreciate",ko:"높이 평가하다",note:"가치를 인정하되 한발 거리를 둠"},{en:"acknowledge",ko:"인정하다",note:"존재만 받아들이는 가장 신중한 톤"}],[{en:"committed",ko:"전념하는",note:"가장 강한 의지 표명"},{en:"open",ko:"열려 있는",note:"가능성은 열되 약속은 미루는 어감"},{en:"receptive",ko:"수용적인",note:"들을 자세는 있다는 절제된 표현"}],[{en:"reconciled",ko:"조율되다",note:"상충을 맞춰 화해시킨다는 외교어"},{en:"aligned",ko:"부합하다",note:"방향을 나란히 맞춘다는 어감"},{en:"consistent",ko:"일관되다",note:"모순 없음을 강조하는 중립어"}],[{en:"constraints",ko:"제약",note:"어쩔 수 없는 한계라는 변호조"},{en:"priorities",ko:"우선순위",note:"선택의 문제로 점잖게 돌림"},{en:"obligations",ko:"의무",note:"지켜야 할 책무임을 강조"}],[{en:"revisit",ko:"재검토하다",note:"다시 들여다보자는 부드러운 제안"},{en:"refine",ko:"다듬다",note:"큰 틀은 두고 세부만 손본다는 어감"},{en:"calibrate",ko:"조정하다",note:"정밀하게 맞춰 가자는 전문조"}]],example:{en:"We welcome the spirit of the proposal and remain committed to dialogue, but any commitment must be reconciled with our domestic constraints, so I'd urge that we revisit the timeline together.",ko:"제안의 취지를 환영하며 대화에 계속 전념합니다. 다만 어떤 약속도 자국의 제약과 조율되어야 하므로, 일정을 함께 재검토할 것을 촉구합니다."},alternatives:[{en:"We're prepared to explore common ground in good faith.",ko:"우리는 선의로 공통 기반을 모색할 준비가 되어 있습니다.",note:"협력 의지를 내비치는 외교 상투구"},{en:"I'd rather we not prejudge the outcome at this stage.",ko:"현 단계에서 결과를 예단하지 않는 편이 좋겠습니다.",note:"결론을 못 박길 미루는 완곡한 견제"},{en:"Let me take that back to my capital for consultation.",ko:"그 사안은 본국에 가져가 협의하겠습니다.",note:"즉답을 피하는 외교가의 정중한 보류"}]},{id:"dlg-c2-nuance-001",level:"C2",situation:"nuance",context:{en:"Tactfully disagreeing with a respected mentor",ko:"존경하는 멘토에게 정중하게 이견을 표함"},prompt:{en:"I assume you agree this is the only sensible path forward?",ko:"이게 유일하게 합리적인 길이라는 데 동의하시겠죠?"},template:"I see the {0} of your reasoning, and I'm {1} to defer to your experience, but I can't quite {2} the sense that we're {3} a subtler option — might it be worth {4}?",blanks:[[{en:"merit",ko:"타당함",note:"논리의 옳은 가치를 점잖게 인정"},{en:"force",ko:"설득력",note:"밀어붙이는 논리의 힘을 강조"},{en:"logic",ko:"논리",note:"추론 구조 자체를 중립적으로 지칭"}],[{en:"inclined",ko:"~하고 싶은",note:"은근히 그쪽으로 기우는 격식체"},{en:"tempted",ko:"~하고 싶은 마음이 드는",note:"솔깃하나 망설임이 깔린 어감"},{en:"minded",ko:"~할 의향이 있는",note:"그럴 마음을 격식 있게 밝힘"}],[{en:"shake",ko:"떨치다",note:"느낌을 떨쳐낸다는 구어 관용구"},{en:"dismiss",ko:"떨쳐내다",note:"생각을 의식적으로 물린다는 어감"},{en:"escape",ko:"벗어나다",note:"그 느낌에서 빠져나오지 못함을 강조"}],[{en:"overlooking",ko:"간과하는",note:"무심코 못 보고 지나침"},{en:"foreclosing",ko:"미리 닫아버리는",note:"가능성을 앞당겨 차단한다는 비판"},{en:"missing",ko:"놓치는",note:"쉬운 일상어로 누락을 지적"}],[{en:"pausing on",ko:"잠시 멈춰 생각해보는 것",note:"잠깐 머물러 곱씹자는 부드러운 제안"},{en:"reconsidering",ko:"재고하는 것",note:"다시 따져 보자는 정공법"},{en:"exploring",ko:"탐색해보는 것",note:"열린 자세로 더 살펴보자는 어감"}]],example:{en:"I see the merit of your reasoning, and I'm inclined to defer to your experience, but I can't quite shake the sense that we're overlooking a subtler option — might it be worth pausing on?",ko:"선생님 논리의 타당함은 알겠고 경험을 존중하고 싶습니다. 다만 더 미묘한 선택지를 간과하고 있다는 느낌을 떨칠 수가 없는데, 잠시 멈춰 생각해볼 가치가 있지 않을까요?"},alternatives:[{en:"I'd hate to second-guess you, but something gives me pause.",ko:"감히 의문을 제기하긴 싫지만, 어딘가 마음에 걸리는 게 있습니다.",note:"재고를 꺼리는 척 운을 떼는 완곡 화법"},{en:"Perhaps I'm splitting hairs, yet the distinction matters here.",ko:"제가 사소한 걸 따지는 걸지도 모르지만, 여기선 그 차이가 중요합니다.",note:"트집 잡는다 미리 인정하며 핵심을 짚는 관용구"},{en:"Forgive me for pushing back, but I'm not wholly convinced.",ko:"이견을 내서 죄송하지만, 완전히 납득되지는 않습니다.",note:"양해를 구하고 반론하는 정중한 공식"}]},{id:"dlg-c2-negotiation-advanced-001",level:"C2",situation:"negotiation-advanced",context:{en:"Countering an aggressive opening offer in a high-stakes deal",ko:"큰 거래에서 공격적인 첫 제안에 맞대응함"},prompt:{en:"This is our final number — take it or leave it.",ko:"이게 최종 금액입니다. 받든지 말든지 하세요."},template:"I'd be {0} if I pretended that figure {1}, so let me be {2}: we can {3} on terms, but not on a number that {4} the value we bring.",blanks:[[{en:"disingenuous",ko:"솔직하지 못한",note:"모르는 척 둘러대는 점잖은 격식 어휘"},{en:"dishonest",ko:"정직하지 못한",note:"거짓이라고 직설적으로 단정"},{en:"insincere",ko:"진심이 아닌",note:"본심과 다르게 둘러대는 점잖은 문어체"}],[{en:"works for us",ko:"우리에게 맞다",note:"실익이 된다는 캐주얼 구어"},{en:"reflects reality",ko:"현실을 반영한다",note:"실상과 맞는지 따지는 어감"},{en:"holds up",ko:"타당하다",note:"검증에도 버틴다는 구어 관용구"}],[{en:"candid",ko:"솔직한",note:"꾸밈없이 터놓는 정중한 솔직함"},{en:"direct",ko:"직설적인",note:"에두르지 않고 곧장 말함"},{en:"straight",ko:"단도직입적인",note:"가장 격의 없는 구어체"}],[{en:"be flexible",ko:"유연하게 대응하다",note:"융통성 있다는 무난한 표현"},{en:"find room",ko:"여지를 찾다",note:"여백을 만들어 본다는 협상 어감"},{en:"move",ko:"양보하다",note:"입장을 옮긴다는 짧고 단단한 구어"}],[{en:"discounts",ko:"깎아내린다",note:"가치를 일부러 낮춰 본다는 어감"},{en:"ignores",ko:"무시한다",note:"아예 셈에 넣지 않는다는 강한 톤"},{en:"undervalues",ko:"과소평가한다",note:"제값보다 낮게 매긴다는 격식체"}]],example:{en:"I'd be disingenuous if I pretended that figure works for us, so let me be candid: we can be flexible on terms, but not on a number that discounts the value we bring.",ko:"그 금액이 우리에게 맞는 척한다면 솔직하지 못한 거겠죠. 그래서 솔직히 말씀드립니다. 조건은 유연하게 갈 수 있지만, 우리가 제공하는 가치를 깎아내리는 금액은 안 됩니다."},alternatives:[{en:"Let's not anchor the conversation on a number neither of us believes.",ko:"둘 다 믿지 않는 금액에 대화를 고정시키지 맙시다.",note:"협상의 앵커링 함정을 경계하는 전문 화법"},{en:"I'm walking in good faith, but that's a non-starter.",ko:"선의로 임하고 있지만, 그건 협상 대상이 될 수 없습니다.",note:"성의는 보이되 선을 못 박는 단호한 구어"},{en:"Help me understand what's driving that figure.",ko:"그 금액의 근거가 무엇인지 이해할 수 있게 도와주시죠.",note:"추궁 대신 근거를 캐묻는 부드러운 압박"}]},{id:"dlg-c2-public-speaking-001",level:"C2",situation:"public-speaking",context:{en:"Opening a keynote address to an industry audience",ko:"업계 청중 앞에서 기조연설을 시작함"},prompt:{en:"The floor is yours — what's your message tonight?",ko:"발언권을 드리겠습니다. 오늘 밤 전하실 메시지는요?"},template:"We {0} at an inflection point, and I want to {1} a comfortable assumption tonight: that progress is {2}. It isn't — it's {3}, and it demands that we {4} the way we think.",blanks:[[{en:"stand",ko:"서 있다",note:"굳건히 자리한다는 연설조 기본형"},{en:"find ourselves",ko:"처해 있다",note:"어쩌다 그 상황에 놓였다는 뉘앙스"},{en:"gather",ko:"모여 있다",note:"함께 모인 청중을 끌어안는 어감"}],[{en:"challenge",ko:"도전하다",note:"통념에 정면으로 맞서겠다는 선언"},{en:"unsettle",ko:"흔들다",note:"안주를 일부러 뒤흔든다는 강조"},{en:"question",ko:"의문을 제기하다",note:"당연시를 되묻는 절제된 표현"}],[{en:"inevitable",ko:"필연적인",note:"막을 수 없이 닥친다는 어감"},{en:"guaranteed",ko:"보장된",note:"확실히 약속됐다는 구어적 강조"},{en:"automatic",ko:"저절로 되는",note:"노력 없이 저절로 굴러간다는 어감"}],[{en:"earned",ko:"쟁취되는",note:"노력으로 얻어낸다는 능동적 어감"},{en:"fragile",ko:"허약한",note:"쉬이 깨진다는 위기감 강조"},{en:"hard-won",ko:"힘겹게 얻는",note:"어렵사리 쟁취함을 부각"}],[{en:"rethink",ko:"다시 생각하다",note:"재고를 촉구하는 무난한 표현"},{en:"reimagine",ko:"재상상하다",note:"발상 자체를 새로 그린다는 비전형"},{en:"overhaul",ko:"전면 재정비하다",note:"통째로 뜯어고친다는 강한 어감"}]],example:{en:"We stand at an inflection point, and I want to challenge a comfortable assumption tonight: that progress is inevitable. It isn't — it's earned, and it demands that we rethink the way we think.",ko:"우리는 변곡점에 서 있습니다. 오늘 밤 저는 안일한 가정 하나에 도전하고자 합니다. 진보가 필연적이라는 가정 말입니다. 그렇지 않습니다. 진보는 쟁취되는 것이며, 우리가 사고방식을 다시 생각할 것을 요구합니다."},alternatives:[{en:"Let me begin not with an answer, but with an uncomfortable question.",ko:"답이 아니라 불편한 질문으로 시작하겠습니다.",note:"긴장을 거는 연설 오프닝 정석"},{en:"Tonight I want to speak plainly about something we tend to avoid.",ko:"오늘 밤 우리가 흔히 피하는 무언가에 대해 솔직히 말하고자 합니다.",note:"금기를 정면으로 꺼내는 진솔한 어조"},{en:"The story I'm about to tell begins with a failure of imagination.",ko:"이제 들려드릴 이야기는 상상력의 결핍에서 시작됩니다.",note:"서사로 청중을 끌어들이는 스토리텔링 도입"}]},{id:"dlg-c2-journalism-001",level:"C2",situation:"journalism",context:{en:"A reporter presses a spokesperson at a press briefing",ko:"기자가 브리핑에서 대변인을 추궁함"},prompt:{en:"Isn't it true that the agency knew about the risk months ago?",ko:"당국이 그 위험을 몇 달 전부터 알고 있었다는 게 사실 아닙니까?"},template:"I won't {0} the question, so let me be {1}: there were {2} we should have heeded sooner, and while I won't {3} blame tonight, the public {4} a fuller accounting.",blanks:[[{en:"dodge",ko:"회피하다",note:"잽싸게 피한다는 구어 관용구"},{en:"sidestep",ko:"비껴가다",note:"옆으로 슬쩍 피한다는 어감"},{en:"deflect",ko:"딴 데로 돌리다",note:"화살을 다른 데로 튕긴다는 뉘앙스"}],[{en:"frank",ko:"솔직한",note:"거리낌 없이 터놓는다는 표준어"},{en:"upfront",ko:"터놓고 말하는",note:"처음부터 숨김없이라는 구어"},{en:"transparent",ko:"투명한",note:"감추는 것 없음을 강조하는 격식체"}],[{en:"warning signs",ko:"경고 신호",note:"위험을 알리던 조짐 일반"},{en:"red flags",ko:"위험 징후",note:"확연한 적신호를 뜻하는 구어 관용구"},{en:"indications",ko:"징후",note:"은근한 낌새를 가리키는 중립어"}],[{en:"apportion",ko:"배분하다",note:"책임을 몫대로 나눈다는 격식 어휘"},{en:"assign",ko:"지우다",note:"특정인에게 책임을 매긴다는 어감"},{en:"pin",ko:"전가하다",note:"남에게 콕 떠넘긴다는 구어"}],[{en:"deserves",ko:"받을 자격이 있다",note:"마땅히 누릴 권리라는 일반형"},{en:"is owed",ko:"받아야 마땅하다",note:"빚 갚듯 당연히 줘야 한다는 어감"},{en:"is entitled to",ko:"권리가 있다",note:"법적·당위적 자격을 강조하는 격식체"}]],example:{en:"I won't dodge the question, so let me be frank: there were warning signs we should have heeded sooner, and while I won't apportion blame tonight, the public deserves a fuller accounting.",ko:"질문을 회피하지 않겠습니다. 솔직히 말씀드리죠. 더 빨리 유념했어야 할 경고 신호가 있었고, 오늘 밤 책임을 배분하진 않겠지만, 국민은 더 충실한 해명을 받을 자격이 있습니다."},alternatives:[{en:"I'm not going to hide behind procedure on this one.",ko:"이 사안에서 절차 뒤에 숨지 않겠습니다.",note:"절차 핑계를 안 대겠다는 솔직한 다짐"},{en:"Let me give you a straight answer rather than a talking point.",ko:"준비된 멘트가 아니라 솔직한 답을 드리겠습니다.",note:"정해진 홍보 문구를 거부하는 진솔한 어조"},{en:"We'll release the full timeline once the review concludes.",ko:"검토가 끝나는 대로 전체 경위를 공개하겠습니다.",note:"추궁을 공개 약속으로 받아넘기는 대변인 화법"}]},{id:"dlg-c2-persuasion-advanced-001",level:"C2",situation:"persuasion-advanced",context:{en:"Winning over a skeptical board to back a bold strategy",ko:"회의적인 이사회를 설득해 과감한 전략을 지지하게 함"},prompt:{en:"Why should we gamble on something this unproven?",ko:"이렇게 검증되지 않은 것에 왜 도박을 해야 합니까?"},template:"I'd {0} the framing: the real {1} isn't acting, it's standing still while rivals {2} ahead. What I'm proposing isn't a gamble — it's a {3} bet, and inaction is the one outcome we can't {4}.",blanks:[[{en:"push back on",ko:"반박하다",note:"전제에 정면으로 맞서는 구어 관용구"},{en:"resist",ko:"받아들이지 않다",note:"수용을 거부한다는 절제된 표현"},{en:"recast",ko:"재구성하다",note:"프레임 자체를 다시 짜 친다는 전략어"}],[{en:"risk",ko:"위험",note:"손실 가능성을 가리키는 중립 기본어"},{en:"danger",ko:"위협",note:"임박한 해악을 강조하는 어감"},{en:"gamble",ko:"도박",note:"상대 표현을 되받아쳐 비트는 수사"}],[{en:"pull",ko:"치고 나가다",note:"앞서 빠져나간다는 'pull ahead' 관용구"},{en:"race",ko:"질주하다",note:"전속력으로 달린다는 역동적 어감"},{en:"surge",ko:"급부상하다",note:"한순간에 솟구쳐 오른다는 강조"}],[{en:"calculated",ko:"계산된",note:"리스크를 따져 본 전략임을 강조"},{en:"measured",ko:"신중한",note:"절제되고 균형 잡혔다는 어감"},{en:"disciplined",ko:"절제된",note:"규율로 통제된 베팅임을 부각"}],[{en:"afford",ko:"감당하다",note:"비용을 치를 여력이라는 일반형"},{en:"survive",ko:"견뎌내다",note:"살아남느냐는 생존 차원의 강조"},{en:"stomach",ko:"받아들이다",note:"꾹 참고 삼킨다는 구어적 어감"}]],example:{en:"I'd push back on the framing: the real risk isn't acting, it's standing still while rivals pull ahead. What I'm proposing isn't a gamble — it's a calculated bet, and inaction is the one outcome we can't afford.",ko:"그 전제에 반박하겠습니다. 진짜 위험은 행동하는 게 아니라 경쟁사가 치고 나가는 동안 가만히 있는 겁니다. 제가 제안하는 건 도박이 아니라 계산된 베팅이고, 무행동이야말로 우리가 감당할 수 없는 유일한 결과입니다."},alternatives:[{en:"The status quo is the riskiest position in the room.",ko:"현상 유지야말로 이 자리에서 가장 위험한 선택입니다.",note:"안주를 최대 위험으로 뒤집는 설득 수사"},{en:"Let's not mistake caution for prudence here.",ko:"여기서 몸 사리는 것을 신중함으로 착각하지 맙시다.",note:"겁먹음과 신중함을 가르는 날 선 경구"},{en:"Every great move looked reckless until it paid off.",ko:"모든 위대한 결단은 성과를 내기 전까지 무모해 보였습니다.",note:"결과론을 뒤집어 도전을 정당화하는 명언조"}]},{id:"dlg-c2-formal-discussion-001",level:"C2",situation:"formal-discussion",context:{en:"Mediating between two opposing factions in a committee",ko:"위원회에서 대립하는 두 진영을 중재함"},prompt:{en:"These two positions are simply irreconcilable, aren't they?",ko:"이 두 입장은 그냥 양립 불가능한 것 아닙니까?"},template:"I'd {0} that they're as far apart as they {1}; both sides are {2} the same underlying concern, and if we {3} the rhetoric, I suspect we can {4} a workable middle ground.",blanks:[[{en:"question whether",ko:"~인지 의문이다",note:"단정을 피해 부드럽게 되묻는 중재조"},{en:"doubt that",ko:"~라고 의심한다",note:"그렇지 않을 거라는 회의를 표함"},{en:"dispute that",ko:"~라는 데 이견이 있다",note:"정면으로 이의를 다는 단단한 어감"}],[{en:"appear",ko:"보이다",note:"겉으로 그래 보인다는 격식체"},{en:"seem",ko:"여겨지다",note:"주관적 인상을 담은 무난한 표현"},{en:"look",ko:"보이다",note:"가장 일상적인 구어 표현"}],[{en:"circling",ko:"맴돌고 있다",note:"핵심 주위를 빙빙 돈다는 비유"},{en:"voicing",ko:"표출하고 있다",note:"같은 우려를 소리 내 말한다는 어감"},{en:"grappling with",ko:"씨름하고 있다",note:"힘겹게 붙들고 고심한다는 강조"}],[{en:"set aside",ko:"제쳐두다",note:"잠시 옆으로 미뤄 둔다는 표현"},{en:"strip away",ko:"걷어내다",note:"껍데기를 벗겨낸다는 단호한 어감"},{en:"lower",ko:"누그러뜨리다",note:"수위를 낮춘다는 온건한 표현"}],[{en:"find",ko:"찾아내다",note:"이미 있는 것을 발견한다는 기본형"},{en:"carve out",ko:"마련하다",note:"없던 공간을 깎아 만든다는 어감"},{en:"reach",ko:"도달하다",note:"합의점에 다다른다는 격식체"}]],example:{en:"I'd question whether they're as far apart as they appear; both sides are circling the same underlying concern, and if we set aside the rhetoric, I suspect we can find a workable middle ground.",ko:"두 입장이 보이는 만큼 멀리 떨어져 있는지 의문입니다. 양측 모두 같은 근본적 우려를 맴돌고 있고, 수사를 제쳐두면 실현 가능한 중간 지점을 찾을 수 있으리라 봅니다."},alternatives:[{en:"Let's identify where we genuinely diverge, not where we merely sound different.",ko:"말투만 다른 지점이 아니라 진짜로 갈라지는 지점을 짚어봅시다.",note:"표현 차이와 본질 차이를 가르는 중재 화법"},{en:"I sense more common ground here than either side will admit.",ko:"어느 쪽도 인정하지 않으려는 것보다 공통점이 더 많다고 느낍니다.",note:"숨은 합의 여지를 짚어 화해를 유도"},{en:"Perhaps the disagreement is one of emphasis, not of principle.",ko:"어쩌면 이견은 원칙이 아니라 강조점의 차이일지 모릅니다.",note:"대립을 사소화해 접점을 넓히는 외교적 표현"}]},{id:"dlg-c2-critique-001",level:"C2",situation:"critique",context:{en:"Offering a candid critique of a colleague's manuscript",ko:"동료의 원고에 솔직한 비평을 함"},prompt:{en:"Be honest — does the argument actually hold together?",ko:"솔직히 말해줘. 논지가 실제로 잘 짜여 있어?"},template:"The prose is {0} and the thesis is {1}, but the argument {2} in the third section, where the evidence feels {3} — tighten that, and the whole piece will {4}.",blanks:[[{en:"elegant",ko:"우아한",note:"기품 있고 세련된 문체를 칭찬"},{en:"polished",ko:"세련된",note:"공들여 다듬은 완성도를 평가"},{en:"assured",ko:"자신감 있는",note:"흔들림 없는 필치임을 강조"}],[{en:"compelling",ko:"설득력 있는",note:"거부하기 힘든 호소력을 칭찬"},{en:"ambitious",ko:"야심 찬",note:"포부가 큰 시도임을 평가하되 부담 암시"},{en:"provocative",ko:"도발적인",note:"논쟁을 부르는 자극성을 짚음"}],[{en:"falters",ko:"흔들리다",note:"기세가 비틀거린다는 완곡한 지적"},{en:"loses its footing",ko:"발을 헛디디다",note:"디딜 곳을 잃는다는 생생한 비유"},{en:"thins out",ko:"빈약해지다",note:"내용이 점점 얇아진다는 어감"}],[{en:"threadbare",ko:"빈약한",note:"닳아 해진 듯 부실하다는 비유"},{en:"selectively chosen",ko:"선별적으로 고른",note:"입맛대로 골랐다는 점잖은 비판"},{en:"stretched",ko:"억지로 끼워 맞춘",note:"근거를 무리하게 늘려 댔다는 어감"}],[{en:"cohere",ko:"탄탄해지다",note:"조각들이 하나로 맞물린다는 학술어"},{en:"land",ko:"설득력을 얻다",note:"메시지가 정확히 꽂힌다는 구어"},{en:"hold up",ko:"버텨내다",note:"비판에도 무너지지 않는다는 어감"}]],example:{en:"The prose is elegant and the thesis is compelling, but the argument falters in the third section, where the evidence feels threadbare — tighten that, and the whole piece will cohere.",ko:"문장은 우아하고 논지는 설득력 있어. 다만 세 번째 절에서 논증이 흔들리는데, 거기 증거가 빈약하게 느껴져. 그 부분을 조이면 글 전체가 탄탄해질 거야."},alternatives:[{en:"It's nearly there — the bones are sound, but the joints are loose.",ko:"거의 다 됐어. 뼈대는 튼튼한데 이음새가 헐거워.",note:"골격과 연결을 빗댄 비평 비유"},{en:"I'd kill a few of your darlings to let the core breathe.",ko:"핵심이 숨 쉬게 아끼는 표현 몇 개는 과감히 덜어내겠어.",note:"'kill your darlings' 작법 격언을 인용"},{en:"The conclusion overreaches what the evidence can bear.",ko:"결론이 증거가 감당할 수 있는 범위를 넘어서고 있어.",note:"근거 대비 결론의 과욕을 짚는 비평 표현"}]}],"DIALOGUE_VERSION",0,1],575777)}]);